// Anime-Sama API - TypeScript port based on anime-sama-cli
// This module scrapes anime-sama.org as a FALLBACK source for missing episodes

const ANIME_SAMA_PROVIDERS = [
  'https://anime-sama.si/',
  'https://anime-sama.tv/',
  'https://anime-sama.pw/',
];

// Language IDs supported by anime-sama
type LangId = 'vostfr' | 'vf' | 'vf1' | 'vf2' | 'va' | 'vcn' | 'vj' | 'vkr' | 'vqc';

interface AnimeSamaCatalogue {
  url: string;
  name: string;
  alternativeNames: string[];
  genres: string[];
  categories: string[];
  languages: string[];
  imageUrl: string;
}

interface AnimeSamaSeason {
  url: string;
  name: string;
  serieName: string;
  langId: LangId;
}

interface AnimeSamaEpisode {
  index: number;
  name: string;
  players: string[]; // Video URLs
  langId: LangId;
}

// Cache
const siteUrlCache: { url: string; timestamp: number } | null = null;
const CACHE_TTL = 60 * 60 * 1000; // 1 hour

// Rate limiting
let lastRequestTime = 0;
const MIN_REQUEST_INTERVAL = 300;

async function rateLimit() {
  const now = Date.now();
  if (now - lastRequestTime < MIN_REQUEST_INTERVAL) {
    await new Promise(r => setTimeout(r, MIN_REQUEST_INTERVAL - (now - lastRequestTime)));
  }
  lastRequestTime = Date.now();
}

/**
 * Find the active anime-sama URL
 */
export async function findActiveSiteUrl(): Promise<string | null> {
  try {
    rateLimit();
    const response = await fetch(ANIME_SAMA_PROVIDERS[2]); // Try .pw first (redirect page)

    if (!response.ok) return null;

    const html = await response.text();

    // Look for the actual site URL
    const match = html.match(/href="(.+?)">Accéder à Anime-Sama/i);
    if (match) {
      return match[1].endsWith('/') ? match[1] : match[1] + '/';
    }

    // Fallback to trying direct access
    for (const provider of ANIME_SAMA_PROVIDERS) {
      rateLimit();
      const test = await fetch(provider);
      if (test.ok) {
        return provider;
      }
    }

    return null;
  } catch {
    return null;
  }
}

/**
 * Search for anime on anime-sama
 */
export async function searchAnimeSama(query: string): Promise<AnimeSamaCatalogue[]> {
  try {
    const siteUrl = await findActiveSiteUrl();
    if (!siteUrl) return [];

    rateLimit();
    const searchUrl = `${siteUrl}catalogue/?search=${encodeURIComponent(query)}`;
    const response = await fetch(searchUrl);

    if (!response.ok) return [];

    const html = await response.text();
    return parseCataloguesFromHtml(html, siteUrl);
  } catch (error) {
    console.error('Anime-Sama search error:', error);
    return [];
  }
}

/**
 * Parse catalogue entries from HTML
 */
function parseCataloguesFromHtml(html: string, siteUrl: string): AnimeSamaCatalogue[] {
  const catalogues: AnimeSamaCatalogue[] = [];

  // Remove script tags for cleaner parsing
  const cleanHtml = html.replace(/<script[\s\S]*?<\/script>/gi, '');

  // Regex to find catalogue entries
  const regex = new RegExp(
    `href="(${siteUrl}catalogue/[^"]+)"[\\s\\S]*?` +
    `src="([^"]+)"[\\s\\S]*?` +
    `<h2[^>]*>([^<]+)[\\s\\S]*?` +
    `<p[^>]*>([^<]*)[\\s\\S]*?` +
    `<p[^>]*>([^<]*)[\\s\\S]*?` +
    `<p[^>]*>([^<]*)[\\s\\S]*?` +
    `<p[^>]*>([^<]*)`,
    'gi'
  );

  let match;
  while ((match = regex.exec(cleanHtml)) !== null) {
    const [, url, imageUrl, name, altNames, genres, categories, languages] = match;

    catalogues.push({
      url: decodeHTMLEntities(url),
      name: decodeHTMLEntities(name).trim(),
      alternativeNames: altNames ? decodeHTMLEntities(altNames).split(', ').filter(Boolean) : [],
      genres: genres ? decodeHTMLEntities(genres).split(/,\s*|\s*-\s*/) : [],
      categories: categories ? decodeHTMLEntities(categories).split(', ') : [],
      languages: languages ? decodeHTMLEntities(languages).split(', ') : [],
      imageUrl: decodeHTMLEntities(imageUrl),
    });
  }

  return catalogues;
}

/**
 * Get seasons for an anime
 */
export async function getSeasons(catalogueUrl: string): Promise<AnimeSamaSeason[]> {
  try {
    rateLimit();
    const response = await fetch(catalogueUrl);
    if (!response.ok) return [];

    const html = await response.text();

    // Remove JS comments
    const cleanHtml = html.replace(/\/\*[\s\S]*?\*\//g, '').replace(/<!--[\s\S]*?-->/g, '');

    // Find seasons - pattern: panneauAnime("Name", "link");
    const regex = /panneauAnime\("(.+?)",\s*"(.+?)(?:vostfr|vf)"\);/gi;

    const seasons: AnimeSamaSeason[] = [];
    let match;

    while ((match = regex.exec(cleanHtml)) !== null) {
      const [, name, link] = match;
      const langId = (link.toLowerCase().includes('vf') ? 'vf' : 'vostfr') as LangId;

      seasons.push({
        url: catalogueUrl + link,
        name: decodeHTMLEntities(name),
        serieName: catalogueUrl.split('/').filter(Boolean).pop() || '',
        langId,
      });
    }

    return seasons;
  } catch (error) {
    console.error('Error fetching seasons:', error);
    return [];
  }
}

/**
 * Get episodes for a season
 */
export async function getEpisodes(seasonUrl: string): Promise<AnimeSamaEpisode[]> {
  try {
    rateLimit();

    // Try both vostfr and vf
    const langUrls = [
      seasonUrl.endsWith('/') ? seasonUrl : seasonUrl + '/',
      seasonUrl.replace(/\/$/, '') + '/vostfr/',
      seasonUrl.replace(/\/$/, '') + '/vf/',
    ];

    for (const url of langUrls) {
      const episodes = await fetchEpisodesFromSeasonPage(url);
      if (episodes.length > 0) {
        return episodes;
      }
    }

    return [];
  } catch (error) {
    console.error('Error fetching episodes:', error);
    return [];
  }
}

async function fetchEpisodesFromSeasonPage(url: string): Promise<AnimeSamaEpisode[]> {
  try {
    rateLimit();
    const response = await fetch(url);
    if (!response.ok) return [];

    const html = await response.text();

    // Find episodes.js URL
    const jsMatch = html.match(/episodes\.js\?filever=\d+/);
    if (!jsMatch) return [];

    // Fetch the episodes JS
    rateLimit();
    const jsResponse = await fetch(url + jsMatch[0]);
    if (!jsResponse.ok) return [];

    const jsContent = await jsResponse.text();

    // Parse eps arrays: eps1 = ['url1', 'url2', ...]
    const episodes: AnimeSamaEpisode[] = [];
    const epsRegex = /eps(\d+)\s*=\s*\[([\s\S]+?)\];/g;

    let match;
    while ((match = epsRegex.exec(jsContent)) !== null) {
      const epNum = parseInt(match[1]);
      const playersStr = match[2];

      // Extract URLs
      const urlRegex = /'([^']+)'/g;
      const players: string[] = [];
      let urlMatch;
      while ((urlMatch = urlRegex.exec(playersStr)) !== null) {
        players.push(urlMatch[1]);
      }

      if (players.length > 0) {
        // Fix vidmoly.to -> vidmoly.net
        players.forEach((p, i) => {
          if (p.includes('vidmoly.to')) {
            players[i] = p.replace('vidmoly.to', 'vidmoly.net');
          }
        });

        episodes.push({
          index: epNum,
          name: `Episode ${epNum}`,
          players,
          langId: url.includes('/vf') ? 'vf' : 'vostfr',
        });
      }
    }

    // Sort by episode number
    episodes.sort((a, b) => a.index - b.index);

    return episodes;
  } catch {
    return [];
  }
}

/**
 * Get episode video URL - main function to use as fallback
 */
export async function getEpisodeUrl(
  animeTitle: string,
  seasonNumber: number,
  episodeNumber: number,
  preferLang: 'vf' | 'vostfr' = 'vostfr'
): Promise<{ url: string; source: string } | null> {
  try {
    // 1. Search for the anime
    const catalogues = await searchAnimeSama(animeTitle);

    if (catalogues.length === 0) {
      // Try with cleaned title
      const cleanTitle = animeTitle
        .replace(/\s*(saison|season|s)\s*\d+/i, '')
        .replace(/\s*\(\s*vf\s*\)/i, '')
        .replace(/\s*\(\s*vostfr\s*\)/i, '')
        .trim();

      if (cleanTitle !== animeTitle) {
        return getEpisodeUrl(cleanTitle, seasonNumber, episodeNumber, preferLang);
      }
      return null;
    }

    // 2. Get seasons from first matching catalogue
    const catalogue = catalogues[0];
    const seasons = await getSeasons(catalogue.url);

    if (seasons.length === 0) return null;

    // 3. Find the requested season
    const seasonMatch = seasons.find(s => {
      const seasonNum = s.name.match(/\d+/);
      return seasonNum ? parseInt(seasonNum[0]) === seasonNumber : false;
    }) || seasons[0];

    // 4. Get episodes
    const episodes = await getEpisodes(seasonMatch.url);

    if (episodes.length === 0) return null;

    // 5. Find the requested episode
    const episode = episodes.find(e => e.index === episodeNumber);

    if (!episode || episode.players.length === 0) return null;

    // 6. Return the best player URL
    // Prefer certain players: sibnet, vidmoly, sendvid
    const preferredPlayers = ['sibnet', 'vidmoly', 'sendvid', 'uptostream'];

    for (const preferred of preferredPlayers) {
      const player = episode.players.find(p => p.toLowerCase().includes(preferred));
      if (player) {
        return { url: player, source: 'anime-sama' };
      }
    }

    // Fallback to first player
    return { url: episode.players[0], source: 'anime-sama' };

  } catch (error) {
    console.error('Anime-Sama getEpisodeUrl error:', error);
    return null;
  }
}

/**
 * Get max episodes available for an anime
 */
export async function getMaxEpisodes(animeTitle: string): Promise<number> {
  try {
    const catalogues = await searchAnimeSama(animeTitle);
    if (catalogues.length === 0) return 0;

    const seasons = await getSeasons(catalogues[0].url);
    if (seasons.length === 0) return 0;

    const episodes = await getEpisodes(seasons[0].url);
    if (episodes.length === 0) return 0;

    return Math.max(...episodes.map(e => e.index));
  } catch {
    return 0;
  }
}

// Helper
function decodeHTMLEntities(str: string): string {
  return str
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/&nbsp;/g, ' ');
}

// Export cache stats
export function getAnimeSamaCacheStats() {
  return {
    siteUrl: siteUrlCache,
  };
}

