/**
 * Anime-Sama API Module
 * Sources: anime-sama.to (main) / anime-sama.pw (redirect)
 * Based on: https://github.com/Edd-io/Aniteve & https://github.com/can-oktay404/anisama-cli
 */

// URLs
const AS_REDIRECT_URL = 'https://anime-sama.pw/';
const AS_CATALOGUE_PATH = '/catalogue/?type%5B0%5D=Anime&page=';
const AS_CATALOGUE_LISTING = '/catalogue/listing_all.php';

// Available video players
const AVAILABLE_PLAYERS = ['sibnet', 'vidmoly', 'sendvid', 'oneupload'];

// Cache
let cachedBaseUrl: string | null = null;
let lastUrlFetch = 0;
const URL_CACHE_DURATION = 12 * 60 * 60 * 1000; // 12 hours

// Headers for requests
const HEADERS = {
  'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
  'Accept': 'text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8',
  'Accept-Language': 'en-US,en;q=0.5',
  'Connection': 'keep-alive',
};

export interface AnimeSamaAnime {
  title: string;
  url: string;
  image: string;
  alternativeTitles: string;
  genres: string[];
  languages: string[];
}

export interface AnimeSamaSeason {
  name: string;
  url: string;
  lang: string; // 'vf' or 'vostfr'
}

export interface AnimeSamaEpisode {
  episodeNumber: number;
  sources: {
    player: string;
    url: string;
  }[];
}

/**
 * Fetch the current anime-sama URL (follows redirect from .pw to .to)
 */
async function getBaseUrl(): Promise<string> {
  // Check cache
  if (cachedBaseUrl && Date.now() - lastUrlFetch < URL_CACHE_DURATION) {
    return cachedBaseUrl;
  }

  try {
    // Fetch the redirect page
    const response = await fetch(AS_REDIRECT_URL, {
      redirect: 'follow',
      headers: HEADERS,
    });

    const finalUrl = response.url;

    // Extract base URL (e.g., https://anime-sama.to/)
    const urlObj = new URL(finalUrl);
    cachedBaseUrl = `${urlObj.origin}/`;
    lastUrlFetch = Date.now();

    console.log(`[Anime-Sama] Base URL: ${cachedBaseUrl}`);
    return cachedBaseUrl;
  } catch (error) {
    console.error('[Anime-Sama] Failed to get base URL:', error);
    // Fallback to .to
    return 'https://anime-sama.to/';
  }
}

/**
 * Search for anime on anime-sama
 */
export async function searchAnimeSama(query: string): Promise<AnimeSamaAnime[]> {
  const baseUrl = await getBaseUrl();
  const searchUrl = `${baseUrl}catalogue/?search=${encodeURIComponent(query)}`;

  try {
    const response = await fetch(searchUrl, { headers: HEADERS });

    if (!response.ok) {
      console.error(`[Anime-Sama] Search failed: ${response.status}`);
      return [];
    }

    const html = await response.text();
    return parseAnimeList(html);
  } catch (error) {
    console.error('[Anime-Sama] Search error:', error);
    return [];
  }
}

/**
 * Get all animes (paginated)
 */
export async function getAllAnimes(page: number = 1): Promise<AnimeSamaAnime[]> {
  const baseUrl = await getBaseUrl();
  const url = `${baseUrl}${AS_CATALOGUE_PATH}${page}`;

  try {
    const response = await fetch(url, { headers: HEADERS });

    if (!response.ok) {
      return [];
    }

    const html = await response.text();
    return parseAnimeList(html);
  } catch (error) {
    console.error('[Anime-Sama] Get all animes error:', error);
    return [];
  }
}

/**
 * Parse anime list from HTML
 */
function parseAnimeList(html: string): AnimeSamaAnime[] {
  const animes: AnimeSamaAnime[] = [];

  // Find the catalogue list
  const listMatch = html.match(/id="list_catalog"[\s\S]*?(?=<\/div>\s*<\/div>|$)/);
  if (!listMatch) {
    // Try alternative pattern
    const altMatch = html.match(/id="list_catalog"[\s\S]*?<div class="[^"]*flex[^"]*"[^>]*>([\s\S]*?)<\/div>\s*<\/div>/);
    if (!altMatch) return [];
  }

  // Extract anime entries - pattern: <div class="shrink-0">...</div>
  const animePattern = /<div[^>]*class="[^"]*shrink-0[^"]*"[^>]*>([\s\S]*?)<\/div>\s*(?=<div[^>]*class="[^"]*shrink-0|<\/div>\s*<\/div>)/g;

  let match;
  while ((match = animePattern.exec(html)) !== null) {
    const animeHtml = match[1];

    try {
      // Extract title
      const titleMatch = animeHtml.match(/<h2[^>]*>([^<]+)<\/h2>/);
      const title = titleMatch ? titleMatch[1].trim() : '';

      // Extract URL
      const urlMatch = animeHtml.match(/<a[^>]*href="([^"]+)"[^>]*>/);
      const url = urlMatch ? urlMatch[1] : '';

      // Extract image
      const imgMatch = animeHtml.match(/<img[^>]*src="([^"]+)"[^>]*>/);
      const image = imgMatch ? imgMatch[1] : '';

      // Extract alternative titles
      const altMatch = animeHtml.match(/<p[^>]*class="[^"]*alternate-titles[^"]*"[^>]*>([^<]+)<\/p>/);
      const alternativeTitles = altMatch ? altMatch[1].trim() : '';

      // Extract genres and languages
      const genres = extractGenres(animeHtml);
      const languages = extractLanguages(animeHtml);

      if (title && url) {
        animes.push({
          title,
          url,
          image,
          alternativeTitles,
          genres,
          languages,
        });
      }
    } catch (e) {
      // Skip malformed entries
    }
  }

  return animes;
}

/**
 * Extract genres from anime HTML
 */
function extractGenres(html: string): string[] {
  const genres: string[] = [];

  // Pattern for info-value paragraphs
  const genreMatch = html.match(/<p[^>]*class="[^"]*info-value[^"]*"[^>]*>([^<]+)<\/p>/);
  if (genreMatch) {
    genres.push(...genreMatch[1].split(',').map(g => g.trim()));
  }

  return genres;
}

/**
 * Extract available languages from anime HTML
 */
function extractLanguages(html: string): string[] {
  const languages: string[] = [];

  // Find all info-value paragraphs
  const matches = html.matchAll(/<p[^>]*class="[^"]*info-value[^"]*"[^>]*>([^<]+)<\/p>/g);
  const allMatches = [...matches];

  // Languages are usually in the 3rd info-value
  if (allMatches.length >= 3) {
    const langStr = allMatches[2][1];
    languages.push(...langStr.split(',').map(l => l.trim().toLowerCase()));
  }

  return languages;
}

/**
 * Get seasons for an anime
 */
export async function getSeasons(animeUrl: string): Promise<AnimeSamaSeason[]> {
  const baseUrl = await getBaseUrl();
  const fullUrl = animeUrl.startsWith('http') ? animeUrl : `${baseUrl}${animeUrl.replace(/^\//, '')}`;

  try {
    const response = await fetch(fullUrl, { headers: HEADERS });

    if (!response.ok) {
      return [];
    }

    const html = await response.text();
    return parseSeasons(html, baseUrl);
  } catch (error) {
    console.error('[Anime-Sama] Get seasons error:', error);
    return [];
  }
}

/**
 * Parse seasons from anime page HTML
 * Looks for: panneauAnime("Season Name", "url");
 */
function parseSeasons(html: string, baseUrl: string): AnimeSamaSeason[] {
  const seasons: AnimeSamaSeason[] = [];

  // Remove JS comments first
  let cleanHtml = html.replace(/\/\*[\s\S]*?\*\//g, '');
  cleanHtml = cleanHtml.replace(/<!--[\s\S]*?-->/g, '');

  // Pattern: panneauAnime("Name", "url");
  const pattern = /panneauAnime\("([^"]+)",\s*"([^"]+)"\)/g;

  let match;
  while ((match = pattern.exec(cleanHtml)) !== null) {
    const name = match[1];
    const url = match[2];

    // Extract language from URL (ends with /vf or /vostfr)
    const langMatch = url.match(/\/(vf|vostfr)\/?$/i);
    const lang = langMatch ? langMatch[1].toLowerCase() : 'vostfr';

    // Skip films usually
    if (name.toLowerCase().includes('film') && name.toLowerCase() === 'nom') {
      continue;
    }

    seasons.push({
      name,
      url: url.startsWith('http') ? url : `${baseUrl}${url.replace(/^\//, '')}`,
      lang: lang as 'vf' | 'vostfr',
    });
  }

  return seasons;
}

/**
 * Get episodes for a season
 */
export async function getEpisodes(seasonUrl: string): Promise<AnimeSamaEpisode[]> {
  const baseUrl = await getBaseUrl();

  // Determine the language from URL
  const isVf = seasonUrl.includes('/vf');
  const langPath = isVf ? 'vf' : 'vostfr';

  // Construct episode JS URL
  const cleanUrl = seasonUrl.replace(/\/(vf|vostfr)\/?$/, '');
  const episodesUrl = `${cleanUrl}/${langPath}/episodes.js`;

  try {
    const response = await fetch(episodesUrl, { headers: HEADERS });

    if (!response.ok) {
      // Try with filever parameter
      const responseWithVer = await fetch(`${episodesUrl}?filever=1`, { headers: HEADERS });
      if (!responseWithVer.ok) {
        return [];
      }
      return parseEpisodesJs(await responseWithVer.text(), baseUrl);
    }

    return parseEpisodesJs(await response.text(), baseUrl);
  } catch (error) {
    console.error('[Anime-Sama] Get episodes error:', error);
    return [];
  }
}

/**
 * Parse episodes.js content
 * Format: var eps1 = ["url1", "url2", ...]; var eps2 = [...];
 */
function parseEpisodesJs(jsContent: string, baseUrl: string): AnimeSamaEpisode[] {
  const episodes: AnimeSamaEpisode[] = [];

  // Find all episode arrays: var eps1 = [...], var eps2 = [...], etc.
  const arrayPattern = /var\s+eps(\d+)\s*=\s*\[([\s\S]*?)\];/g;

  const episodeArrays: Map<number, string[]> = new Map();

  let match;
  while ((match = arrayPattern.exec(jsContent)) !== null) {
    const arrayNum = parseInt(match[1], 10);
    const arrayContent = match[2];

    // Extract URLs from array
    const urls: string[] = [];
    const urlPattern = /'([^']+)'/g;
    let urlMatch;
    while ((urlMatch = urlPattern.exec(arrayContent)) !== null) {
      let url = urlMatch[1];
      // Fix vidmoly.to -> vidmoly.net
      url = url.replace('vidmoly.to', 'vidmoly.net');
      urls.push(url);
    }

    episodeArrays.set(arrayNum, urls);
  }

  // Transpose arrays: eps1 has URLs for all episodes from server 1, etc.
  // We need to group by episode number
  const maxEpisodes = Math.max(...[...episodeArrays.values()].map(arr => arr.length));

  for (let epNum = 1; epNum <= maxEpisodes; epNum++) {
    const sources: AnimeSamaEpisode['sources'] = [];

    for (const [serverNum, urls] of episodeArrays) {
      if (urls[epNum - 1]) {
        const url = urls[epNum - 1];

        // Determine player type
        let player = 'unknown';
        for (const p of AVAILABLE_PLAYERS) {
          if (url.includes(p)) {
            player = p;
            break;
          }
        }

        // Only include known players
        if (player !== 'unknown') {
          sources.push({ player, url });
        }
      }
    }

    if (sources.length > 0) {
      episodes.push({
        episodeNumber: epNum,
        sources,
      });
    }
  }

  return episodes;
}

/**
 * Get embed URL for a player
 */
export function getEmbedUrl(player: string, url: string): string {
  switch (player) {
    case 'sibnet':
      // Sibnet URLs are already embed URLs
      return url;

    case 'vidmoly':
      // Convert to embed URL
      if (url.includes('/embed-')) {
        return url;
      }
      const vidmolyMatch = url.match(/vidmoly\.net\/(?:embed-)?([a-zA-Z0-9]+)/);
      if (vidmolyMatch) {
        return `https://vidmoly.net/embed-${vidmolyMatch[1]}.html`;
      }
      return url;

    case 'sendvid':
      // Convert to embed URL
      if (url.includes('/embed/')) {
        return url;
      }
      const sendvidMatch = url.match(/sendvid\.com\/([a-zA-Z0-9]+)/);
      if (sendvidMatch) {
        return `https://sendvid.com/embed/${sendvidMatch[1]}`;
      }
      return url;

    case 'oneupload':
      return url;

    default:
      return url;
  }
}

/**
 * Find episode for an anime (main function for fallback)
 */
export async function findAnimeSamaEpisode(
  animeTitle: string,
  seasonNumber: number,
  episodeNumber: number,
  lang: 'vf' | 'vostfr'
): Promise<{ url: string; player: string; source: 'anime-sama' } | null> {
  try {
    // Search for the anime
    const searchResults = await searchAnimeSama(animeTitle);

    if (searchResults.length === 0) {
      return null;
    }

    // Find best match
    const anime = searchResults.find(a => 
      a.title.toLowerCase() === animeTitle.toLowerCase() ||
      a.alternativeTitles.toLowerCase().includes(animeTitle.toLowerCase())
    ) || searchResults[0];

    // Get seasons
    const seasons = await getSeasons(anime.url);

    // Find the requested season
    let targetSeason = seasons.find(s => {
      const seasonMatch = s.name.match(/\d+/);
      const sNum = seasonMatch ? parseInt(seasonMatch[0], 10) : 1;
      return sNum === seasonNumber && s.lang === lang;
    });

    // Fallback: find by language only
    if (!targetSeason) {
      targetSeason = seasons.find(s => s.lang === lang);
    }

    // Fallback: any season
    if (!targetSeason && seasons.length > 0) {
      targetSeason = seasons[0];
    }

    if (!targetSeason) {
      return null;
    }

    // Get episodes
    const episodes = await getEpisodes(targetSeason.url);

    // Find the requested episode
    const episode = episodes.find(ep => ep.episodeNumber === episodeNumber);

    if (!episode || episode.sources.length === 0) {
      return null;
    }

    // Prefer sibnet, then vidmoly
    const preferredOrder = ['sibnet', 'vidmoly', 'sendvid', 'oneupload'];
    let bestSource = episode.sources[0];

    for (const preferred of preferredOrder) {
      const found = episode.sources.find(s => s.player === preferred);
      if (found) {
        bestSource = found;
        break;
      }
    }

    const embedUrl = getEmbedUrl(bestSource.player, bestSource.url);

    return {
      url: embedUrl,
      player: bestSource.player,
      source: 'anime-sama',
    };
  } catch (error) {
    console.error('[Anime-Sama] Find episode error:', error);
    return null;
  }
}

/**
 * Check if anime-sama has an anime
 */
export async function checkAnimeSamaAvailability(animeTitle: string): Promise<boolean> {
  const results = await searchAnimeSama(animeTitle);
  return results.length > 0;
}

/**
 * Get latest episodes (from homepage)
 */
export async function getLatestEpisodes(): Promise<{
  title: string;
  season: string;
  episode: number;
  url: string;
}[]> {
  const baseUrl = await getBaseUrl();

  try {
    const response = await fetch(baseUrl, { headers: HEADERS });

    if (!response.ok) {
      return [];
    }

    const html = await response.text();
    const latest: { title: string; season: string; episode: number; url: string }[] = [];

    // Parse the "ajouts animes" section
    const sectionMatch = html.match(/id="containerAjoutsAnimes"[\s\S]*?(?=<\/div>\s*<\/div>|$)/);
    if (!sectionMatch) return [];

    const section = sectionMatch[0];

    // Extract titles
    const titlePattern = /<h1[^>]*>([^<]+)<\/h1>/g;
    // Extract URLs
    const urlPattern = /<a[^>]*href="([^"]+)"[^>]*>/g;
    // Extract episode numbers
    const epPattern = /Episode\s*(\d+)/gi;

    // This is simplified - real parsing would be more complex
    // For now, return empty array as this requires more detailed parsing

    return latest;
  } catch (error) {
    console.error('[Anime-Sama] Get latest error:', error);
    return [];
  }
}

