/**
 * TMDB (The Movie Database) Service
 * Provides high-quality images, French descriptions, and detailed metadata
 * API Documentation: https://developers.themoviedb.org/3
 */

const TMDB_API_KEY = process.env.TMDB_API_KEY || '';
const TMDB_BASE_URL = 'https://api.themoviedb.org/3';
const TMDB_IMAGE_BASE = 'https://image.tmdb.org/t/p';

// Image sizes
export const TMDB_POSTER_SIZES = {
  small: '/w342',
  medium: '/w500',
  large: '/w780',
  original: '/original',
};

export const TMDB_BACKDROP_SIZES = {
  small: '/w300',
  medium: '/w780',
  large: '/w1280',
  original: '/original',
};

interface TMDBSearchResult {
  id: number;
  name: string;
  original_name: string;
  overview: string;
  poster_path: string | null;
  backdrop_path: string | null;
  first_air_date: string;
  vote_average: number;
  vote_count: number;
  popularity: number;
  genre_ids: number[];
  original_language: string;
  origin_country: string[];
}

interface TMDBTVShow {
  id: number;
  name: string;
  original_name: string;
  overview: string;
  poster_path: string | null;
  backdrop_path: string | null;
  first_air_date: string;
  last_air_date: string | null;
  vote_average: number;
  vote_count: number;
  popularity: number;
  genres: { id: number; name: string }[];
  number_of_seasons: number;
  number_of_episodes: number;
  seasons: TMDBSeason[];
  networks: { id: number; name: string; logo_path: string | null }[];
  status: string;
  type: string;
  languages: string[];
}

interface TMDBSeason {
  id: number;
  season_number: number;
  name: string;
  overview: string;
  poster_path: string | null;
  episode_count: number;
  air_date: string;
}

interface TMDBEpisode {
  id: number;
  name: string;
  overview: string;
  still_path: string | null;
  episode_number: number;
  season_number: number;
  air_date: string;
  vote_average: number;
  runtime: number | null;
}

interface TMDBCredits {
  cast: {
    id: number;
    name: string;
    character: string;
    profile_path: string | null;
    order: number;
  }[];
  crew: {
    id: number;
    name: string;
    job: string;
    department: string;
    profile_path: string | null;
  }[];
}

interface TMDBVideos {
  results: {
    id: string;
    key: string;
    name: string;
    site: string;
    type: string; // Trailer, Teaser, Clip, etc.
    official: boolean;
  }[];
}

interface TMDBExternalIds {
  imdb_id: string | null;
  tvdb_id: number | null;
  mal_id: number | null; // MyAnimeList ID via external sources
}

// Genre mapping for anime
const ANIME_GENRE_IDS: Record<number, string> = {
  16: 'Animation',
  10759: 'Action & Adventure',
  10765: 'Sci-Fi & Fantasy',
  35: 'Comedy',
  18: 'Drama',
  10768: 'War & Politics',
  37: 'Western',
  10762: 'Kids',
  9648: 'Mystery',
  10763: 'News',
  10764: 'Reality',
  10766: 'Soap',
  10767: 'Talk',
  36: 'History',
  10402: 'Music',
  10749: 'Romance',
  878: 'Science Fiction',
  80: 'Crime',
  99: 'Documentary',
  10751: 'Family',
  14: 'Fantasy',
  36: 'History',
  27: 'Horror',
  10402: 'Music',
  9648: 'Mystery',
  10749: 'Romance',
  878: 'Science Fiction',
  53: 'Thriller',
  10752: 'War',
  37: 'Western',
};

/**
 * Check if TMDB API key is configured
 */
export function isTMDBConfigured(): boolean {
  return TMDB_API_KEY.length > 0;
}

/**
 * Make a TMDB API request
 */
async function tmdbFetch(endpoint: string, params: Record<string, string> = {}): Promise<any> {
  if (!isTMDBConfigured()) {
    throw new Error('TMDB API key not configured');
  }

  const url = new URL(`${TMDB_BASE_URL}${endpoint}`);
  url.searchParams.append('api_key', TMDB_API_KEY);
  url.searchParams.append('language', 'fr-FR'); // French language preference

  Object.entries(params).forEach(([key, value]) => {
    url.searchParams.append(key, value);
  });

  const response = await fetch(url.toString(), {
    headers: {
      'Content-Type': 'application/json',
    },
  });

  if (!response.ok) {
    throw new Error(`TMDB API error: ${response.status}`);
  }

  return response.json();
}

/**
 * Search for anime by name
 */
export async function searchTMDBAnime(query: string): Promise<TMDBSearchResult[]> {
  try {
    // Search in TV shows (most anime are categorized as TV shows)
    const data = await tmdbFetch('/search/tv', {
      query,
      page: '1',
      include_adult: 'false',
    });

    // Filter for animation genre (16) or Japanese origin
    const results = data.results?.filter((show: TMDBSearchResult) => {
      // Include if it's animation or from Japan
      return show.genre_ids?.includes(16) || 
             show.original_language === 'ja' ||
             show.origin_country?.includes('JP');
    }) || [];

    return results;
  } catch (error) {
    console.error('[TMDB] Search error:', error);
    return [];
  }
}

/**
 * Get TV show details by ID
 */
export async function getTMDBTVShow(id: number): Promise<TMDBTVShow | null> {
  try {
    const data = await tmdbFetch(`/tv/${id}`, {
      append_to_response: 'external_ids',
    });
    return data;
  } catch (error) {
    console.error(`[TMDB] Error fetching TV show ${id}:`, error);
    return null;
  }
}

/**
 * Get TV show by external ID (IMDb, TVDB, etc.)
 */
export async function getTMDBByExternalId(imdbId: string): Promise<TMDBTVShow | null> {
  try {
    const findResult = await tmdbFetch(`/find/${imdbId}`, {
      external_source: 'imdb_id',
    });

    if (findResult.tv_results?.length > 0) {
      return getTMDBTVShow(findResult.tv_results[0].id);
    }
    return null;
  } catch (error) {
    console.error(`[TMDB] Error finding by external ID:`, error);
    return null;
  }
}

/**
 * Get season details
 */
export async function getTMDBSeason(tvId: number, seasonNumber: number): Promise<{
  season: TMDBSeason;
  episodes: TMDBEpisode[];
} | null> {
  try {
    const data = await tmdbFetch(`/tv/${tvId}/season/${seasonNumber}`);
    return {
      season: {
        id: data.id,
        season_number: data.season_number,
        name: data.name,
        overview: data.overview,
        poster_path: data.poster_path,
        episode_count: data.episode_count,
        air_date: data.air_date,
      },
      episodes: data.episodes || [],
    };
  } catch (error) {
    console.error(`[TMDB] Error fetching season:`, error);
    return null;
  }
}

/**
 * Get episode details
 */
export async function getTMDBEpisode(
  tvId: number, 
  seasonNumber: number, 
  episodeNumber: number
): Promise<TMDBEpisode | null> {
  try {
    const data = await tmdbFetch(`/tv/${tvId}/season/${seasonNumber}/episode/${episodeNumber}`);
    return data;
  } catch (error) {
    console.error(`[TMDB] Error fetching episode:`, error);
    return null;
  }
}

/**
 * Get credits (cast & crew)
 */
export async function getTMDBCredits(tvId: number): Promise<TMDBCredits | null> {
  try {
    const data = await tmdbFetch(`/tv/${tvId}/credits`);
    return data;
  } catch (error) {
    console.error(`[TMDB] Error fetching credits:`, error);
    return null;
  }
}

/**
 * Get videos (trailers, etc.)
 */
export async function getTMDBVideos(tvId: number): Promise<TMDBVideos['results'] | null> {
  try {
    const data = await tmdbFetch(`/tv/${tvId}/videos`);
    return data.results || [];
  } catch (error) {
    console.error(`[TMDB] Error fetching videos:`, error);
    return null;
  }
}

/**
 * Get external IDs (IMDb, TVDB, MAL, etc.)
 */
export async function getTMDBExternalIds(tvId: number): Promise<TMDBExternalIds | null> {
  try {
    const data = await tmdbFetch(`/tv/${tvId}/external_ids`);
    return {
      imdb_id: data.imdb_id,
      tvdb_id: data.tvdb_id,
      mal_id: data.mal_id || null,
    };
  } catch (error) {
    console.error(`[TMDB] Error fetching external IDs:`, error);
    return null;
  }
}

/**
 * Get similar/recommended TV shows
 */
export async function getTMDBSimilar(tvId: number): Promise<TMDBSearchResult[]> {
  try {
    const data = await tmdbFetch(`/tv/${tvId}/similar`);
    return data.results || [];
  } catch (error) {
    console.error(`[TMDB] Error fetching similar:`, error);
    return [];
  }
}

/**
 * Get recommendations
 */
export async function getTMDBRecommendations(tvId: number): Promise<TMDBSearchResult[]> {
  try {
    const data = await tmdbFetch(`/tv/${tvId}/recommendations`);
    return data.results || [];
  } catch (error) {
    console.error(`[TMDB] Error fetching recommendations:`, error);
    return [];
  }
}

/**
 * Build image URL
 */
export function getTMDBImageUrl(path: string | null, size: string = 'original'): string | null {
  if (!path) return null;
  return `${TMDB_IMAGE_BASE}${size}${path}`;
}

/**
 * Get poster URL
 */
export function getTMDBPosterUrl(path: string | null, size: keyof typeof TMDB_POSTER_SIZES = 'large'): string | null {
  return getTMDBImageUrl(path, TMDB_POSTER_SIZES[size]);
}

/**
 * Get backdrop URL
 */
export function getTMDBBackdropUrl(path: string | null, size: keyof typeof TMDB_BACKDROP_SIZES = 'original'): string | null {
  return getTMDBImageUrl(path, TMDB_BACKDROP_SIZES[size]);
}

/**
 * Get genre name by ID
 */
export function getGenreName(genreId: number): string {
  return ANIME_GENRE_IDS[genreId] || 'Unknown';
}

/**
 * Convert genre IDs to names
 */
export function genreIdsToNames(genreIds: number[]): string[] {
  return genreIds.map(id => getGenreName(id)).filter(Boolean);
}

/**
 * Search and get the best match for an anime name
 */
export async function findBestTMDBMatch(
  animeName: string,
  year?: number
): Promise<TMDBTVShow | null> {
  try {
    const results = await searchTMDBAnime(animeName);

    if (results.length === 0) return null;

    // Sort by popularity and name similarity
    const sorted = results.sort((a, b) => {
      // Prefer exact name match
      const aNameMatch = a.name.toLowerCase() === animeName.toLowerCase() ||
                         a.original_name.toLowerCase() === animeName.toLowerCase();
      const bNameMatch = b.name.toLowerCase() === animeName.toLowerCase() ||
                         b.original_name.toLowerCase() === animeName.toLowerCase();

      if (aNameMatch && !bNameMatch) return -1;
      if (!aNameMatch && bNameMatch) return 1;

      // If year is provided, prefer shows from that year
      if (year) {
        const aYear = parseInt(a.first_air_date?.substring(0, 4) || '0');
        const bYear = parseInt(b.first_air_date?.substring(0, 4) || '0');
        const aYearDiff = Math.abs(aYear - year);
        const bYearDiff = Math.abs(bYear - year);

        if (aYearDiff < bYearDiff) return -1;
        if (aYearDiff > bYearDiff) return 1;
      }

      // Sort by popularity
      return b.popularity - a.popularity;
    });

    // Get full details for the best match
    if (sorted[0]) {
      return getTMDBTVShow(sorted[0].id);
    }

    return null;
  } catch (error) {
    console.error(`[TMDB] Error finding best match for "${animeName}":`, error);
    return null;
  }
}

/**
 * Enrich anime data with TMDB information
 * Returns enriched data or null if TMDB is not available
 */
export async function enrichWithTMDB(animeName: string, year?: number): Promise<{
  coverImage: string | null;
  bannerImage: string | null;
  description: string | null;
  year: number | null;
  rating: number | null;
  genres: string[];
  status: string | null;
  numberOfSeasons: number | null;
  numberOfEpisodes: number | null;
  trailerUrl: string | null;
} | null> {
  if (!isTMDBConfigured()) {
    return null;
  }

  try {
    const show = await findBestTMDBMatch(animeName, year);

    if (!show) return null;

    // Get trailer
    const videos = await getTMDBVideos(show.id);
    const trailer = videos?.find(v => 
      v.type === 'Trailer' && 
      v.site === 'YouTube' && 
      v.official
    ) || videos?.find(v => v.type === 'Trailer' && v.site === 'YouTube');

    return {
      coverImage: getTMDBPosterUrl(show.poster_path, 'large'),
      bannerImage: getTMDBBackdropUrl(show.backdrop_path, 'original'),
      description: show.overview || null,
      year: show.first_air_date ? parseInt(show.first_air_date.substring(0, 4)) : null,
      rating: show.vote_average || null,
      genres: show.genres?.map(g => g.name) || [],
      status: show.status || null,
      numberOfSeasons: show.number_of_seasons || null,
      numberOfEpisodes: show.number_of_episodes || null,
      trailerUrl: trailer ? `https://www.youtube.com/watch?v=${trailer.key}` : null,
    };
  } catch (error) {
    console.error(`[TMDB] Error enriching "${animeName}":`, error);
    return null;
  }
}

/**
 * Combined enrichment: TMDB (priority) → AniList (fallback)
 * This function tries TMDB first, then falls back to AniList if TMDB fails
 */
export async function getAnimeMetadata(
  animeName: string,
  year?: number,
  anilistFallback?: () => Promise<any>
): Promise<{
  coverImage: string | null;
  bannerImage: string | null;
  description: string | null;
  year: number | null;
  rating: number | null;
  genres: string[];
  source: 'tmdb' | 'anilist' | 'none';
}> {
  // Try TMDB first if configured
  if (isTMDBConfigured()) {
    const tmdbData = await enrichWithTMDB(animeName, year);
    if (tmdbData && (tmdbData.coverImage || tmdbData.bannerImage)) {
      return {
        coverImage: tmdbData.coverImage,
        bannerImage: tmdbData.bannerImage,
        description: tmdbData.description,
        year: tmdbData.year,
        rating: tmdbData.rating,
        genres: tmdbData.genres,
        source: 'tmdb',
      };
    }
  }

  // Fall back to AniList if provided
  if (anilistFallback) {
    try {
      const anilistData = await anilistFallback();
      return {
        ...anilistData,
        source: 'anilist',
      };
    } catch (error) {
      console.error('[Metadata] AniList fallback failed:', error);
    }
  }

  return {
    coverImage: null,
    bannerImage: null,
    description: null,
    year: null,
    rating: null,
    genres: [],
    source: 'none',
  };
}

const tmdbService = {
  isTMDBConfigured,
  searchTMDBAnime,
  getTMDBTVShow,
  getTMDBSeason,
  getTMDBEpisode,
  getTMDBCredits,
  getTMDBVideos,
  getTMDBExternalIds,
  getTMDBSimilar,
  getTMDBRecommendations,
  getTMDBPosterUrl,
  getTMDBBackdropUrl,
  enrichWithTMDB,
  getAnimeMetadata,
};

export default tmdbService;

