// AniList GraphQL API service for anime images and metadata

const ANILIST_API = 'https://graphql.anilist.co';

interface AniListMedia {
  id: number;
  title: {
    romaji: string;
    english: string | null;
    native: string | null;
  };
  coverImage: {
    large: string;
    medium: string;
    extraLarge: string;
  } | null;
  bannerImage: string | null;
  description: string | null;
  seasonYear: number | null;
  episodes: number | null;
  status: string;
  genres: string[];
}

interface AniListResponse {
  data: {
    Media: AniListMedia | null;
    Page: {
      media: AniListMedia[];
    } | null;
  };
}

// Cache for anime images (in-memory, 1 hour TTL)
const imageCache = new Map<string, {
  data: AniListMedia | null;
  timestamp: number;
}>();
const CACHE_TTL = 60 * 60 * 1000; // 1 hour

// Rate limiting
let lastRequestTime = 0;
const MIN_REQUEST_INTERVAL = 200; // 200ms between requests

async function rateLimitedFetch(query: string, variables: Record<string, unknown>): Promise<AniListResponse> {
  const now = Date.now();
  const timeSinceLastRequest = now - lastRequestTime;

  if (timeSinceLastRequest < MIN_REQUEST_INTERVAL) {
    await new Promise(resolve => setTimeout(resolve, MIN_REQUEST_INTERVAL - timeSinceLastRequest));
  }

  lastRequestTime = Date.now();

  const response = await fetch(ANILIST_API, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({ query, variables }),
  });

  if (!response.ok) {
    throw new Error(`AniList API error: ${response.status}`);
  }

  return response.json();
}

// Search for anime by title
export async function searchAnimeImage(title: string): Promise<AniListMedia | null> {
  const cacheKey = title.toLowerCase().trim();

  // Check cache
  const cached = imageCache.get(cacheKey);
  if (cached && Date.now() - cached.timestamp < CACHE_TTL) {
    return cached.data;
  }

  try {
    // First try exact search
    const exactQuery = `
      query ($search: String) {
        Media(search: $search, type: ANIME, sort: SEARCH_MATCH) {
          id
          title { romaji english native }
          coverImage { large medium extraLarge }
          bannerImage
          description
          seasonYear
          episodes
          status
          genres
        }
      }
    `;

    let result = await rateLimitedFetch(exactQuery, { search: title });

    if (result.data?.Media) {
      imageCache.set(cacheKey, { data: result.data.Media, timestamp: Date.now() });
      return result.data.Media;
    }

    // If not found, try with cleaned title (remove season indicators, etc.)
    const cleanTitle = title
      .replace(/\s*(saison|season|s)\s*\d+/i, '')
      .replace(/\s*\(\s*vf\s*\)/i, '')
      .replace(/\s*\(\s*vostfr\s*\)/i, '')
      .replace(/\s*-\s*$/, '')
      .trim();

    if (cleanTitle !== title && cleanTitle.length > 2) {
      result = await rateLimitedFetch(exactQuery, { search: cleanTitle });

      if (result.data?.Media) {
        imageCache.set(cacheKey, { data: result.data.Media, timestamp: Date.now() });
        return result.data.Media;
      }
    }

    // Not found
    imageCache.set(cacheKey, { data: null, timestamp: Date.now() });
    return null;

  } catch (error) {
    console.error(`AniList search error for "${title}":`, error);
    return null;
  }
}

// Batch search for multiple anime titles (with concurrent limit)
export async function batchSearchAnimeImages(
  titles: string[],
  concurrency: number = 5
): Promise<Map<string, AniListMedia | null>> {
  const results = new Map<string, AniListMedia | null>();

  // Process in batches
  for (let i = 0; i < titles.length; i += concurrency) {
    const batch = titles.slice(i, i + concurrency);
    const promises = batch.map(async (title) => {
      const result = await searchAnimeImage(title);
      return { title, result };
    });

    const batchResults = await Promise.all(promises);
    for (const { title, result } of batchResults) {
      results.set(title, result);
    }
  }

  return results;
}

// Get cover image URL from AniList result
export function getCoverImage(media: AniListMedia | null): string | null {
  if (!media?.coverImage) return null;
  return media.coverImage.extraLarge || media.coverImage.large || media.coverImage.medium || null;
}

// Get banner image URL from AniList result
export function getBannerImage(media: AniListMedia | null): string | null {
  return media?.bannerImage || null;
}

// Get description from AniList result (cleaned)
export function getDescription(media: AniListMedia | null): string | null {
  if (!media?.description) return null;
  // Remove HTML tags
  return media.description.replace(/<[^>]*>/g, '').trim();
}

// Get year from AniList result
export function getYear(media: AniListMedia | null): number | null {
  return media?.seasonYear || null;
}

// Export cache stats for debugging
export function getCacheStats() {
  return {
    size: imageCache.size,
    entries: Array.from(imageCache.entries()).map(([key, value]) => ({
      title: key,
      hasData: value.data !== null,
      age: Date.now() - value.timestamp,
    })),
  };
}

