// Frivox Anime Data API - https://github.com/frivoxfr/ani-data
const FRIVOX_DATA_URL = 'https://raw.githubusercontent.com/frivoxfr/ani-data/refs/heads/main/anime_data.json';

export interface FrivoxMedia {
  name: string;
  lang: 'vf' | 'vostfr';
  media_type: string;
  season: number;
  episodes: string[];
}

export interface FrivoxData {
  media: FrivoxMedia[];
}

// Cache for the data
let cachedData: FrivoxData | null = null;
let lastFetchTime = 0;
const CACHE_DURATION = 60 * 60 * 1000; // 1 hour

// Fetch all anime data from Frivox
export async function fetchFrivoxData(): Promise<FrivoxData> {
  // Return cached data if still valid
  if (cachedData && Date.now() - lastFetchTime < CACHE_DURATION) {
    return cachedData;
  }

  try {
    const response = await fetch(FRIVOX_DATA_URL, {
      headers: {
        'Accept': 'application/json',
      },
    });

    if (!response.ok) {
      throw new Error(`Failed to fetch Frivox data: ${response.status}`);
    }

    const data: FrivoxData = await response.json();
    cachedData = data;
    lastFetchTime = Date.now();

    console.log(`Loaded ${data.media.length} anime entries from Frivox`);
    return data;
  } catch (error) {
    console.error('Error fetching Frivox data:', error);

    // Return cached data even if expired
    if (cachedData) {
      console.log('Using expired cache');
      return cachedData;
    }

    throw error;
  }
}

// Get all unique anime names
export async function getAllAnimeNames(): Promise<string[]> {
  const data = await fetchFrivoxData();
  const names = new Set<string>();

  for (const media of data.media) {
    names.add(media.name);
  }

  return Array.from(names).sort();
}

// Get anime by name
export async function getAnimeByName(name: string): Promise<FrivoxMedia[]> {
  const data = await fetchFrivoxData();
  return data.media.filter(m => 
    m.name.toLowerCase() === name.toLowerCase()
  );
}

// Search anime by name (fuzzy)
export async function searchAnimeByName(query: string): Promise<string[]> {
  const data = await fetchFrivoxData();
  const lowerQuery = query.toLowerCase();

  const matches = new Set<string>();

  for (const media of data.media) {
    if (media.name.toLowerCase().includes(lowerQuery)) {
      matches.add(media.name);
    }
  }

  return Array.from(matches).sort();
}

// Get available languages for an anime
export async function getAvailableLanguages(name: string): Promise<('vf' | 'vostfr')[]> {
  const seasons = await getAnimeByName(name);
  const languages = new Set<'vf' | 'vostfr'>();

  for (const season of seasons) {
    languages.add(season.lang);
  }

  return Array.from(languages);
}

// Get seasons for an anime (with optional language filter)
export async function getSeasons(name: string, lang?: 'vf' | 'vostfr'): Promise<FrivoxMedia[]> {
  const allSeasons = await getAnimeByName(name);

  if (lang) {
    return allSeasons.filter(s => s.lang === lang);
  }

  return allSeasons.sort((a, b) => a.season - b.season);
}

// Get episodes for a specific season
export async function getEpisodes(
  name: string, 
  season: number, 
  lang: 'vf' | 'vostfr' = 'vostfr'
): Promise<string[]> {
  const data = await fetchFrivoxData();

  const found = data.media.find(m => 
    m.name.toLowerCase() === name.toLowerCase() &&
    m.season === season &&
    m.lang === lang
  );

  return found?.episodes || [];
}

// Get total count
export async function getTotalAnimeCount(): Promise<number> {
  const data = await fetchFrivoxData();
  const uniqueNames = new Set(data.media.map(m => m.name));
  return uniqueNames.size;
}

// Get anime list with pagination
export async function getAnimeList(
  page: number = 1,
  perPage: number = 20,
  search?: string
): Promise<{
  names: string[];
  total: number;
  page: number;
  perPage: number;
  hasMore: boolean;
}> {
  const allNames = search 
    ? await searchAnimeByName(search)
    : await getAllAnimeNames();

  const total = allNames.length;
  const start = (page - 1) * perPage;
  const end = start + perPage;
  const paginatedNames = allNames.slice(start, end);

  return {
    names: paginatedNames,
    total,
    page,
    perPage,
    hasMore: end < total,
  };
}

// Convert to our anime format with combined data
export interface CombinedAnime {
  id: string;
  slug: string;
  title: string;
  coverImage: string | null;
  bannerImage: string | null;
  description: string | null;
  year: number | null;
  episodeCount: number;
  type: string;
  languages: ('vf' | 'vostfr')[];
  seasons: {
    seasonNumber: number;
    episodes: number;
    lang: 'vf' | 'vostfr';
  }[];
  sources: {
    name: string;
    url: string;
  }[];
}

// Get combined anime data
export async function getCombinedAnimeData(name: string): Promise<CombinedAnime | null> {
  const seasons = await getAnimeByName(name);

  if (seasons.length === 0) {
    return null;
  }

  const languages = await getAvailableLanguages(name);
  const totalEpisodes = seasons.reduce((sum, s) => sum + s.episodes.length, 0);

  // Extract video sources
  const sources: { name: string; url: string }[] = [];
  for (const season of seasons) {
    for (const ep of season.episodes) {
      const url = new URL(ep);
      const hostname = url.hostname.replace('www.', '');
      if (!sources.find(s => s.name === hostname)) {
        sources.push({ name: hostname, url: ep });
      }
    }
  }

  return {
    id: name.toLowerCase().replace(/[^a-z0-9]+/g, '-'),
    slug: name.toLowerCase().replace(/[^a-z0-9]+/g, '-'),
    title: name.split(' ').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' '),
    coverImage: null, // Will be enriched from AniList
    bannerImage: null,
    description: null,
    year: null,
    episodeCount: totalEpisodes,
    type: 'Anime',
    languages,
    seasons: seasons.map(s => ({
      seasonNumber: s.season,
      episodes: s.episodes.length,
      lang: s.lang,
    })),
    sources: sources.slice(0, 5),
  };
}

