/**
 * Auto-Update Sync Service
 * Compares Frivox data with Anime-Sama to find missing episodes
 */

import { db } from './db';
import { searchAnimeSama, getSeasons, getEpisodes, getEmbedUrl } from './anime-sama';

// Frivox data URL
const FRIVOX_DATA_URL = 'https://raw.githubusercontent.com/frivoxfr/ani-data/refs/heads/main/anime_data.json';

interface FrivoxMedia {
  name: string;
  lang: 'vf' | 'vostfr';
  media_type: string;
  season: number;
  episodes: string[];
}

interface FrivoxData {
  media: FrivoxMedia[];
}

// Get unique anime names from Frivox with their episode counts
async function getFrivoxAnimeList(): Promise<Map<string, {
  seasons: Map<string, { episodes: number; lang: 'vf' | 'vostfr' }>;
  totalEpisodes: number;
}>> {
  const response = await fetch(FRIVOX_DATA_URL);
  if (!response.ok) {
    throw new Error(`Failed to fetch Frivox data: ${response.status}`);
  }

  const data: FrivoxData = await response.json();
  const animeMap = new Map<string, {
    seasons: Map<string, { episodes: number; lang: 'vf' | 'vostfr' }>;
    totalEpisodes: number;
  }>();

  for (const media of data.media) {
    const name = media.name;

    if (!animeMap.has(name)) {
      animeMap.set(name, { seasons: new Map(), totalEpisodes: 0 });
    }

    const anime = animeMap.get(name)!;
    const seasonKey = `${media.season}-${media.lang}`;

    anime.seasons.set(seasonKey, {
      episodes: media.episodes.length,
      lang: media.lang,
    });
    anime.totalEpisodes += media.episodes.length;
  }

  return animeMap;
}

// Get or create sync status
async function getSyncStatus() {
  let syncStatus = await db.syncStatus.findFirst();

  if (!syncStatus) {
    syncStatus = await db.syncStatus.create({
      data: {},
    });
  }

  return syncStatus;
}

// Update sync status
async function updateSyncStatus(data: Partial<{
  lastSyncAt: Date;
  lastFullSyncAt: Date;
  status: string;
  errorMessage: string | null;
  animesUpdated: number;
  episodesAdded: number;
}>) {
  const syncStatus = await getSyncStatus();
  return db.syncStatus.update({
    where: { id: syncStatus.id },
    data,
  });
}

// Sync a single anime
async function syncAnime(
  animeName: string,
  frivoxData: {
    seasons: Map<string, { episodes: number; lang: 'vf' | 'vostfr' }>;
    totalEpisodes: number;
  }
): Promise<{ episodesAdded: number; hasUpdates: boolean }> {
  const slug = animeName.toLowerCase().replace(/[^a-z0-9]+/g, '-');
  let episodesAdded = 0;
  let hasUpdates = false;

  try {
    // Search on Anime-Sama
    const searchResults = await searchAnimeSama(animeName);

    if (searchResults.length === 0) {
      return { episodesAdded: 0, hasUpdates: false };
    }

    // Find best match
    const anime = searchResults.find(a => 
      a.title.toLowerCase() === animeName.toLowerCase() ||
      a.alternativeTitles.toLowerCase().includes(animeName.toLowerCase())
    ) || searchResults[0];

    // Get seasons from Anime-Sama
    const seasons = await getSeasons(anime.url);

    // Group seasons by language
    const asSeasonsByLang = new Map<string, typeof seasons>();
    for (const season of seasons) {
      const lang = season.lang;
      if (!asSeasonsByLang.has(lang)) {
        asSeasonsByLang.set(lang, []);
      }
      asSeasonsByLang.get(lang)!.push(season);
    }

    // Check each language
    for (const [lang, asSeasons] of asSeasonsByLang) {
      // Get all Frivox episodes for this language
      let frivoxMaxEp = 0;
      for (const [key, data] of frivoxData.seasons) {
        if (data.lang === lang) {
          frivoxMaxEp += data.episodes;
        }
      }

      // Get all episodes from Anime-Sama for this language
      for (const season of asSeasons) {
        try {
          const episodes = await getEpisodes(season.url);

          for (const ep of episodes) {
            // Check if this episode is beyond Frivox's count
            const frivoxSeasonKey = `${season.name.match(/\d+/)?.[0] || '1'}-${lang}`;
            const frivoxSeasonData = frivoxData.seasons.get(frivoxSeasonKey);

            // If episode not in Frivox (either season doesn't exist or episode count exceeded)
            const isExtraEpisode = !frivoxSeasonData || ep.episodeNumber > frivoxSeasonData.episodes;

            if (isExtraEpisode && ep.sources.length > 0) {
              // Prefer sibnet for consistency
              const source = ep.sources.find(s => s.player === 'sibnet') || 
                            ep.sources.find(s => s.player === 'vidmoly') ||
                            ep.sources[0];

              const seasonNum = parseInt(season.name.match(/\d+/)?.[0] || '1', 10);

              // Check if already exists
              const existing = await db.additionalEpisode.findUnique({
                where: {
                  animeSlug_season_episode_lang_source: {
                    animeSlug: slug,
                    season: seasonNum,
                    episode: ep.episodeNumber,
                    lang,
                    source: 'anime-sama',
                  },
                },
              });

              if (!existing) {
                await db.additionalEpisode.create({
                  data: {
                    animeTitle: animeName,
                    animeSlug: slug,
                    season: seasonNum,
                    episode: ep.episodeNumber,
                    lang,
                    source: 'anime-sama',
                    url: getEmbedUrl(source.player, source.url),
                    player: source.player,
                  },
                });
                episodesAdded++;
                hasUpdates = true;
              }
            }
          }
        } catch (e) {
          console.error(`[Sync] Error processing season ${season.name}:`, e);
        }
      }
    }

    // Update or create AnimeUpdate record
    const totalFromAnimeSama = await db.additionalEpisode.count({
      where: { animeSlug: slug },
    });

    await db.animeUpdate.upsert({
      where: { animeSlug: slug },
      create: {
        animeTitle: animeName,
        animeSlug: slug,
        frivoxEpisodes: frivoxData.totalEpisodes,
        totalEpisodes: frivoxData.totalEpisodes + totalFromAnimeSama,
        hasUpdates: totalFromAnimeSama > 0,
      },
      update: {
        frivoxEpisodes: frivoxData.totalEpisodes,
        totalEpisodes: frivoxData.totalEpisodes + totalFromAnimeSama,
        hasUpdates: totalFromAnimeSama > 0,
        lastCheckedAt: new Date(),
      },
    });

  } catch (error) {
    console.error(`[Sync] Error syncing ${animeName}:`, error);
  }

  return { episodesAdded, hasUpdates };
}

// Main sync function
export async function runSync(options: {
  full?: boolean;
  limit?: number;
  skipExisting?: boolean;
} = {}): Promise<{
  success: boolean;
  animesChecked: number;
  animesUpdated: number;
  episodesAdded: number;
  error?: string;
}> {
  const { full = false, limit, skipExisting = false } = options;

  console.log('[Sync] Starting sync...');

  try {
    // Update status
    await updateSyncStatus({ status: 'syncing', errorMessage: null });

    // Get Frivox data
    const frivoxAnimes = await getFrivoxData();

    let animesChecked = 0;
    let animesUpdated = 0;
    let totalEpisodesAdded = 0;

    // Get list of animes to check
    const animeNames = Array.from(frivoxAnimes.keys());

    // If not full sync, prioritize ones not checked recently
    let namesToProcess = animeNames;

    if (!full && skipExisting) {
      const recentChecks = await db.animeUpdate.findMany({
        where: {
          lastCheckedAt: {
            gte: new Date(Date.now() - 24 * 60 * 60 * 1000), // 24 hours
          },
        },
        select: { animeSlug: true },
      });

      const recentSlugs = new Set(recentChecks.map(r => r.animeSlug));
      namesToProcess = animeNames.filter(name => {
        const slug = name.toLowerCase().replace(/[^a-z0-9]+/g, '-');
        return !recentSlugs.has(slug);
      });
    }

    // Apply limit if specified
    if (limit && limit > 0) {
      namesToProcess = namesToProcess.slice(0, limit);
    }

    console.log(`[Sync] Processing ${namesToProcess.length} animes...`);

    // Process in batches of 5
    const batchSize = 5;
    for (let i = 0; i < namesToProcess.length; i += batchSize) {
      const batch = namesToProcess.slice(i, i + batchSize);

      const results = await Promise.all(
        batch.map(async (name) => {
          const frivoxData = frivoxAnimes.get(name)!;
          return syncAnime(name, frivoxData);
        })
      );

      for (const result of results) {
        animesChecked++;
        if (result.hasUpdates) animesUpdated++;
        totalEpisodesAdded += result.episodesAdded;
      }

      // Update status periodically
      if (i % 20 === 0) {
        await updateSyncStatus({
          animesUpdated,
          episodesAdded: totalEpisodesAdded,
        });
        console.log(`[Sync] Progress: ${animesChecked}/${namesToProcess.length}, ${totalEpisodesAdded} new episodes`);
      }
    }

    // Final status update
    await updateSyncStatus({
      lastSyncAt: new Date(),
      lastFullSyncAt: full ? new Date() : undefined,
      status: 'idle',
      animesUpdated,
      episodesAdded: totalEpisodesAdded,
    });

    console.log(`[Sync] Complete! ${animesChecked} checked, ${animesUpdated} updated, ${totalEpisodesAdded} new episodes`);

    return {
      success: true,
      animesChecked,
      animesUpdated,
      episodesAdded: totalEpisodesAdded,
    };

  } catch (error) {
    const errorMessage = error instanceof Error ? error.message : 'Unknown error';
    console.error('[Sync] Error:', errorMessage);

    await updateSyncStatus({
      status: 'error',
      errorMessage,
    });

    return {
      success: false,
      animesChecked: 0,
      animesUpdated: 0,
      episodesAdded: 0,
      error: errorMessage,
    };
  }
}

// Get sync status
export async function getSyncStatusData() {
  const status = await getSyncStatus();
  const updatedAnimes = await db.animeUpdate.count({
    where: { hasUpdates: true },
  });
  const totalExtraEpisodes = await db.additionalEpisode.count({
    where: { isActive: true },
  });

  return {
    ...status,
    updatedAnimes,
    totalExtraEpisodes,
  };
}

// Get additional episodes for an anime
export async function getAdditionalEpisodes(animeSlug: string) {
  return db.additionalEpisode.findMany({
    where: {
      animeSlug,
      isActive: true,
    },
    orderBy: [
      { season: 'asc' },
      { episode: 'asc' },
    ],
  });
}

// Get all animes with updates
export async function getUpdatedAnimes() {
  return db.animeUpdate.findMany({
    where: { hasUpdates: true },
    orderBy: { updatedAt: 'desc' },
  });
}

// Get Frivox data helper
async function getFrivoxData(): Promise<Map<string, {
  seasons: Map<string, { episodes: number; lang: 'vf' | 'vostfr' }>;
  totalEpisodes: number;
}>> {
  const response = await fetch(FRIVOX_DATA_URL);
  if (!response.ok) {
    throw new Error(`Failed to fetch Frivox data: ${response.status}`);
  }

  const data: FrivoxData = await response.json();
  const animeMap = new Map<string, {
    seasons: Map<string, { episodes: number; lang: 'vf' | 'vostfr' }>;
    totalEpisodes: number;
  }>();

  for (const media of data.media) {
    const name = media.name;

    if (!animeMap.has(name)) {
      animeMap.set(name, { seasons: new Map(), totalEpisodes: 0 });
    }

    const anime = animeMap.get(name)!;
    const seasonKey = `${media.season}-${media.lang}`;

    anime.seasons.set(seasonKey, {
      episodes: media.episodes.length,
      lang: media.lang,
    });
    anime.totalEpisodes += media.episodes.length;
  }

  return animeMap;
}

