/**
 * Unified Metadata Service
 * Combines TMDB (priority) and AniList (fallback) for best anime metadata
 */

import { 
  searchAnimeImage, 
  getCoverImage, 
  getBannerImage, 
  getDescription, 
  getYear 
} from './anilist';
import { 
  enrichWithTMDB, 
  isTMDBConfigured,
} from './tmdb';

// Metadata cache interface
interface CachedMetadata {
  id: string;
  animeTitle: string;
  coverImage: string | null;
  bannerImage: string | null;
  description: string | null;
  year: number | null;
  rating: number | null;
  genres: string[];
  source: string; // 'tmdb' | 'anilist'
  timestamp: number;
}

// In-memory cache for faster access
const memoryCache = new Map<string, CachedMetadata>();
const MEMORY_CACHE_TTL = 30 * 60 * 1000; // 30 minutes

/**
 * Get cached metadata
 */
function getCachedMetadata(slug: string): CachedMetadata | null {
  const cached = memoryCache.get(slug);
  if (cached && Date.now() - cached.timestamp < MEMORY_CACHE_TTL) {
    return cached;
  }
  return null;
}

/**
 * Save metadata to cache
 */
function setCachedMetadata(metadata: CachedMetadata): void {
  metadata.timestamp = Date.now();
  memoryCache.set(metadata.id, metadata);
}

/**
 * Clean anime title for better search results
 */
function cleanAnimeTitle(title: string): { cleanTitle: string; year?: number } {
  // Remove common suffixes
  let cleanTitle = title
    .replace(/\s*(saison|season|s)\s*\d+/i, '')
    .replace(/\s*\(\s*vf\s*\)/i, '')
    .replace(/\s*\(\s*vostfr\s*\)/i, '')
    .replace(/\s*\(\s*\d{4}\s*\)/i, '') // Remove year in parentheses
    .replace(/\s*-\s*$/, '')
    .replace(/\s*:\s*$/, '')
    .trim();

  // Extract year from title if present
  const yearMatch = title.match(/\b(19\d{2}|20\d{2})\b/);
  const year = yearMatch ? parseInt(yearMatch[1]) : undefined;

  return { cleanTitle, year };
}

/**
 * Get anime metadata with caching
 * Priority: TMDB → AniList → Cache → None
 */
export async function getAnimeMetadata(
  animeTitle: string,
  options: {
    forceRefresh?: boolean;
    preferTMDB?: boolean;
  } = {}
): Promise<{
  coverImage: string | null;
  bannerImage: string | null;
  description: string | null;
  year: number | null;
  rating: number | null;
  genres: string[];
  source: 'tmdb' | 'anilist' | 'cache' | 'none';
}> {
  const { forceRefresh = false, preferTMDB = true } = options;
  const slug = animeTitle.toLowerCase().replace(/[^a-z0-9]+/g, '-');

  // Check memory cache first
  if (!forceRefresh) {
    const cached = getCachedMetadata(slug);
    if (cached) {
      return {
        coverImage: cached.coverImage,
        bannerImage: cached.bannerImage,
        description: cached.description,
        year: cached.year,
        rating: cached.rating,
        genres: cached.genres,
        source: 'cache',
      };
    }
  }

  const { cleanTitle, year } = cleanAnimeTitle(animeTitle);

  // Try TMDB first if configured and preferred
  if (preferTMDB && isTMDBConfigured()) {
    try {
      const tmdbData = await enrichWithTMDB(cleanTitle, year);

      if (tmdbData && (tmdbData.coverImage || tmdbData.bannerImage)) {
        const result = {
          coverImage: tmdbData.coverImage,
          bannerImage: tmdbData.bannerImage,
          description: tmdbData.description,
          year: tmdbData.year || year || null,
          rating: tmdbData.rating,
          genres: tmdbData.genres,
          source: 'tmdb' as const,
        };

        // Cache the result
        setCachedMetadata({
          id: slug,
          animeTitle,
          ...result,
          source: 'tmdb',
          timestamp: Date.now(),
        });

        return result;
      }
    } catch (error) {
      console.error('[Metadata] TMDB error:', error);
    }
  }

  // Fallback to AniList
  try {
    const anilistData = await searchAnimeImage(cleanTitle);

    if (anilistData) {
      const result = {
        coverImage: getCoverImage(anilistData),
        bannerImage: getBannerImage(anilistData),
        description: getDescription(anilistData),
        year: getYear(anilistData) || year || null,
        rating: null,
        genres: anilistData.genres || [],
        source: 'anilist' as const,
      };

      // Cache the result
      setCachedMetadata({
        id: slug,
        animeTitle,
        ...result,
        source: 'anilist',
        timestamp: Date.now(),
      });

      return result;
    }
  } catch (error) {
    console.error(`[Metadata] AniList error for "${cleanTitle}":`, error);
  }

  // No metadata found
  return {
    coverImage: null,
    bannerImage: null,
    description: null,
    year: year || null,
    rating: null,
    genres: [],
    source: 'none',
  };
}

/**
 * Batch get metadata for multiple anime titles
 */
export async function batchGetMetadata(
  titles: string[],
  concurrency: number = 5
): Promise<Map<string, Awaited<ReturnType<typeof getAnimeMetadata>>>> {
  const results = new Map<string, Awaited<ReturnType<typeof getAnimeMetadata>>>();

  // Process in batches
  for (let i = 0; i < titles.length; i += concurrency) {
    const batch = titles.slice(i, i + concurrency);
    const promises = batch.map(async (title) => {
      const result = await getAnimeMetadata(title);
      return { title, result };
    });

    const batchResults = await Promise.all(promises);
    for (const { title, result } of batchResults) {
      results.set(title, result);
    }
  }

  return results;
}

/**
 * Clear all metadata caches
 */
export function clearMetadataCache(): void {
  memoryCache.clear();
}

/**
 * Get cache statistics
 */
export function getCacheStats() {
  return {
    memoryCacheSize: memoryCache.size,
    entries: Array.from(memoryCache.entries()).map(([key, value]) => ({
      key,
      hasData: value !== null,
      age: Date.now() - value.timestamp,
    })),
  };
}

const metadataService = {
  getAnimeMetadata,
  batchGetMetadata,
  clearMetadataCache,
  getCacheStats,
};

export default metadataService;

