// Video embed service - Multiple sources support

export interface VideoSource {
  source: string;
  url: string;
  quality: string;
  language: 'VF' | 'VOSTFR';
  isWorking: boolean;
}

export interface EpisodeSources {
  episode: number;
  sources: VideoSource[];
}

// Extract video ID from various embed URLs
export function extractVideoId(url: string): { source: string; id: string } | null {
  // Vidmoly patterns
  const vidmolyMatch = url.match(/vidmoly\.(?:to|me)\/(?:embed-|d\/)?([a-zA-Z0-9]+)/i);
  if (vidmolyMatch) return { source: 'vidmoly', id: vidmolyMatch[1] };

  // Sibnet patterns
  const sibnetMatch = url.match(/sibnet\.ru\/(?:shell\.php\?videoid=|video)(\d+)/i);
  if (sibnetMatch) return { source: 'sibnet', id: sibnetMatch[1] };

  // Sendvid patterns
  const sendvidMatch = url.match(/sendvid\.com\/(?:embed\/)?([a-zA-Z0-9]+)/i);
  if (sendvidMatch) return { source: 'sendvid', id: sendvidMatch[1] };

  // Streamtape patterns
  const streamtapeMatch = url.match(/streamtape\.com\/(?:e\/|v\/)?([a-zA-Z0-9]+)/i);
  if (streamtapeMatch) return { source: 'streamtape', id: streamtapeMatch[1] };

  // Doodstream patterns
  const doodMatch = url.match(/dood(?:stream|so|watch)\.(?:com|to|pm)\/(?:e\/|d\/)?([a-zA-Z0-9]+)/i);
  if (doodMatch) return { source: 'doodstream', id: doodMatch[1] };

  // MyStream patterns
  const mystreamMatch = url.match(/mystream\.(?:fun|to|xyz)\/(?:watch\/)?([a-zA-Z0-9]+)/i);
  if (mystreamMatch) return { source: 'mystream', id: mystreamMatch[1] };

  // Filemoon patterns
  const filemoonMatch = url.match(/filemoon\.(?:sx|to|s)\/(?:e\/|d\/)?([a-zA-Z0-9]+)/i);
  if (filemoonMatch) return { source: 'filemoon', id: filemoonMatch[1] };

  return null;
}

// Generate embed URL from source and ID
export function generateEmbedUrl(source: string, id: string): string {
  switch (source.toLowerCase()) {
    case 'vidmoly':
      return `https://vidmoly.to/embed-${id}.html`;
    case 'sibnet':
      return `https://video.sibnet.ru/shell.php?videoid=${id}`;
    case 'sendvid':
      return `https://sendvid.com/embed/${id}`;
    case 'streamtape':
      return `https://streamtape.com/e/${id}`;
    case 'doodstream':
      return `https://doodstream.com/e/${id}`;
    case 'mystream':
      return `https://mystream.to/watch/${id}`;
    case 'filemoon':
      return `https://filemoon.sx/e/${id}`;
    default:
      return '';
  }
}

// Known video sources database for popular anime
// This will be expanded with our own database
const KNOWN_SOURCES: Record<string, EpisodeSources[]> = {
  // Example structure - will be populated from our database
};

// Get sources for an anime episode
export async function getEpisodeSources(
  animeId: string,
  episode: number
): Promise<EpisodeSources | null> {
  // Check our known sources first
  if (KNOWN_SOURCES[animeId]) {
    const found = KNOWN_SOURCES[animeId].find((e) => e.episode === episode);
    if (found) return found;
  }

  // Try to fetch from our API
  try {
    const response = await fetch(`/api/sources/${animeId}/${episode}`);
    if (response.ok) {
      const data = await response.json();
      return data.sources;
    }
  } catch (error) {
    console.error('Error fetching sources:', error);
  }

  return null;
}

// Source priority (best to worst)
export const SOURCE_PRIORITY = [
  { source: 'vidmoly', quality: 'HD', priority: 1 },
  { source: 'sendvid', quality: 'HD', priority: 2 },
  { source: 'filemoon', quality: 'HD', priority: 3 },
  { source: 'streamtape', quality: 'HD', priority: 4 },
  { source: 'doodstream', quality: 'HD', priority: 5 },
  { source: 'mystream', quality: 'SD', priority: 6 },
  { source: 'sibnet', quality: 'SD/HD', priority: 7 },
];

// Sort sources by quality/priority
export function sortSourcesByPriority(sources: VideoSource[]): VideoSource[] {
  return sources.sort((a, b) => {
    const priorityA = SOURCE_PRIORITY.find((s) => s.source === a.source)?.priority || 999;
    const priorityB = SOURCE_PRIORITY.find((s) => s.source === b.source)?.priority || 999;
    return priorityA - priorityB;
  });
}

// Check if a source is available
export async function checkSourceAvailability(url: string): Promise<boolean> {
  try {
    const response = await fetch(url, { method: 'HEAD', timeout: 5000 });
    return response.ok;
  } catch {
    return false;
  }
}

// Video player component data
export interface PlayerData {
  animeId: string;
  animeTitle: string;
  episode: number;
  totalEpisodes: number;
  currentSource: VideoSource;
  availableSources: VideoSource[];
  prevEpisode: number | null;
  nextEpisode: number | null;
}

// Get player data for an episode
export async function getPlayerData(
  animeId: string,
  episode: number,
  language: 'VF' | 'VOSTFR' = 'VOSTFR'
): Promise<PlayerData | null> {
  const sources = await getEpisodeSources(animeId, episode);

  if (!sources || sources.sources.length === 0) {
    return null;
  }

  const filteredSources = sources.sources.filter((s) => s.language === language);
  const sortedSources = sortSourcesByPriority(filteredSources);

  if (sortedSources.length === 0) {
    // Fallback to any language
    const allSorted = sortSourcesByPriority(sources.sources);
    if (allSorted.length === 0) return null;

    return {
      animeId,
      animeTitle: '',
      episode,
      totalEpisodes: 0,
      currentSource: allSorted[0],
      availableSources: allSorted,
      prevEpisode: episode > 1 ? episode - 1 : null,
      nextEpisode: null,
    };
  }

  return {
    animeId,
    animeTitle: '',
    episode,
    totalEpisodes: 0,
    currentSource: sortedSources[0],
    availableSources: sortedSources,
    prevEpisode: episode > 1 ? episode - 1 : null,
    nextEpisode: null,
  };
}

