// Video Source Finder - Scrapes and finds embed links from various sources
import { db } from './db';

export interface VideoSource {
  id: string;
  animeId: string;
  episode: number;
  language: 'VF' | 'VOSTFR';
  source: string;
  url: string;
  embedUrl: string;
  quality: string;
  addedAt: Date;
}

// Video host configurations
const VIDEO_HOSTS = {
  vidmoly: {
    name: 'Vidmoly',
    baseUrl: 'https://vidmoly.to',
    embedFormat: 'https://vidmoly.to/embed-{id}.html',
    quality: '720p/1080p',
  },
  sibnet: {
    name: 'Sibnet',
    baseUrl: 'https://video.sibnet.ru',
    embedFormat: 'https://video.sibnet.ru/shell.php?videoid={id}',
    quality: '480p/720p',
  },
  sendvid: {
    name: 'Sendvid',
    baseUrl: 'https://sendvid.com',
    embedFormat: 'https://sendvid.com/embed/{id}',
    quality: '720p',
  },
  streamtape: {
    name: 'Streamtape',
    baseUrl: 'https://streamtape.com',
    embedFormat: 'https://streamtape.com/e/{id}',
    quality: '720p/1080p',
  },
  doodstream: {
    name: 'Doodstream',
    baseUrl: 'https://doodstream.com',
    embedFormat: 'https://doodstream.com/e/{id}',
    quality: '720p',
  },
  vidoza: {
    name: 'Vidoza',
    baseUrl: 'https://vidoza.net',
    embedFormat: 'https://vidoza.net/embed-{id}.html',
    quality: '720p/1080p',
  },
};

// Generate a unique ID for a video source
function generateId(animeId: string, episode: number, language: string, source: string): string {
  return `${animeId}-${episode}-${language}-${source}`.toLowerCase();
}

// Extract video ID from URL
function extractVideoId(url: string, host: keyof typeof VIDEO_HOSTS): string | null {
  const patterns: Record<string, RegExp> = {
    vidmoly: /vidmoly\.(?:to|net)\/(?:embed-)?([a-zA-Z0-9]+)/,
    sibnet: /sibnet\.ru.*(?:videoid=|video)(\d+)/,
    sendvid: /sendvid\.(?:com|net)\/(?:embed\/)?([a-zA-Z0-9]+)/,
    streamtape: /streamtape\.(?:com|net)\/e\/([a-zA-Z0-9]+)/,
    doodstream: /dood(?:stream)?\.(?:com|net|pm)\/e\/([a-zA-Z0-9]+)/,
    vidoza: /vidoza\.net\/embed-([a-zA-Z0-9]+)/,
  };

  const pattern = patterns[host];
  if (!pattern) return null;

  const match = url.match(pattern);
  return match ? match[1] : null;
}

// Convert URL to embed URL
export function toEmbedUrl(url: string): string {
  // Vidmoly
  if (url.includes('vidmoly')) {
    const id = extractVideoId(url, 'vidmoly');
    if (id) {
      // Check if it's already an embed URL
      if (url.includes('embed-')) return url;
      return `https://vidmoly.to/embed-${id}.html`;
    }
  }

  // Sibnet
  if (url.includes('sibnet')) {
    const id = extractVideoId(url, 'sibnet');
    if (id) {
      return `https://video.sibnet.ru/shell.php?videoid=${id}`;
    }
  }

  // Sendvid
  if (url.includes('sendvid')) {
    const id = extractVideoId(url, 'sendvid');
    if (id) {
      return `https://sendvid.com/embed/${id}`;
    }
  }

  // Streamtape
  if (url.includes('streamtape')) {
    if (url.includes('/e/')) return url;
    const id = extractVideoId(url, 'streamtape');
    if (id) {
      return `https://streamtape.com/e/${id}`;
    }
  }

  // Doodstream
  if (url.includes('dood')) {
    if (url.includes('/e/')) return url;
    const id = extractVideoId(url, 'doodstream');
    if (id) {
      return `https://doodstream.com/e/${id}`;
    }
  }

  // Vidoza
  if (url.includes('vidoza')) {
    if (url.includes('embed')) return url;
    const id = extractVideoId(url, 'vidoza');
    if (id) {
      return `https://vidoza.net/embed-${id}.html`;
    }
  }

  // Return original if no conversion needed or not recognized
  return url;
}

// Detect the video host from URL
export function detectHost(url: string): string {
  if (url.includes('vidmoly')) return 'Vidmoly';
  if (url.includes('sibnet')) return 'Sibnet';
  if (url.includes('sendvid')) return 'Sendvid';
  if (url.includes('streamtape')) return 'Streamtape';
  if (url.includes('dood')) return 'Doodstream';
  if (url.includes('vidoza')) return 'Vidoza';
  return 'Unknown';
}

// Manual video source management - stores in database
export async function addVideoSource(source: {
  animeId: string;
  episode: number;
  language: 'VF' | 'VOSTFR';
  source: string;
  url: string;
  quality?: string;
}): Promise<VideoSource> {
  const embedUrl = toEmbedUrl(source.url);
  const host = detectHost(source.url);
  const id = generateId(source.animeId, source.episode, source.language, host);

  // Store in cache database
  await db.cachedData.upsert({
    where: { key: id },
    create: {
      key: id,
      data: JSON.stringify({
        id,
        animeId: source.animeId,
        episode: source.episode,
        language: source.language,
        source: host,
        url: source.url,
        embedUrl,
        quality: source.quality || VIDEO_HOSTS[host.toLowerCase() as keyof typeof VIDEO_HOSTS]?.quality || 'Unknown',
        addedAt: new Date(),
      }),
      expiresAt: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000), // 30 days
    },
    update: {
      data: JSON.stringify({
        id,
        animeId: source.animeId,
        episode: source.episode,
        language: source.language,
        source: host,
        url: source.url,
        embedUrl,
        quality: source.quality || VIDEO_HOSTS[host.toLowerCase() as keyof typeof VIDEO_HOSTS]?.quality || 'Unknown',
        addedAt: new Date(),
      }),
    },
  });

  return {
    id,
    animeId: source.animeId,
    episode: source.episode,
    language: source.language,
    source: host,
    url: source.url,
    embedUrl,
    quality: source.quality || 'Unknown',
    addedAt: new Date(),
  };
}

// Get video sources for an anime episode
export async function getVideoSources(
  animeId: string,
  episode: number,
  language?: 'VF' | 'VOSTFR'
): Promise<VideoSource[]> {
  const sources: VideoSource[] = [];

  // Query by pattern
  const pattern = `${animeId}-${episode}-${language || ''}`;

  try {
    const cached = await db.cachedData.findMany({
      where: {
        key: { contains: pattern.toLowerCase() },
      },
    });

    for (const entry of cached) {
      const data = JSON.parse(entry.data) as VideoSource;
      if (data.episode === episode) {
        if (!language || data.language === language) {
          sources.push(data);
        }
      }
    }
  } catch (error) {
    console.error('Error fetching video sources:', error);
  }

  return sources;
}

// Get all video sources for an anime
export async function getAllVideoSourcesForAnime(animeId: string): Promise<VideoSource[]> {
  const sources: VideoSource[] = [];

  try {
    const cached = await db.cachedData.findMany({
      where: {
        key: { startsWith: animeId.toLowerCase() },
      },
    });

    for (const entry of cached) {
      sources.push(JSON.parse(entry.data) as VideoSource);
    }
  } catch (error) {
    console.error('Error fetching all video sources:', error);
  }

  return sources.sort((a, b) => a.episode - b.episode);
}

// Delete a video source
export async function deleteVideoSource(id: string): Promise<void> {
  await db.cachedData.delete({
    where: { key: id },
  });
}

// Check if a video URL is valid/accessible
export async function checkVideoUrl(url: string): Promise<boolean> {
  try {
    const response = await fetch(url, { method: 'HEAD', redirect: 'follow' });
    return response.ok || response.status === 302 || response.status === 301;
  } catch {
    return false;
  }
}

// Sample/demo video sources for testing
export const DEMO_SOURCES: VideoSource[] = [
  {
    id: 'demo-1-1-vostfr-vidmoly',
    animeId: 'demon-slayer-kimetsu-no-yaiba',
    episode: 1,
    language: 'VOSTFR',
    source: 'Vidmoly',
    url: 'https://vidmoly.to/w-9qx8e3n3qhm.html',
    embedUrl: 'https://vidmoly.to/embed-9qx8e3n3qhm.html',
    quality: '1080p',
    addedAt: new Date(),
  },
];

// Search for anime on video hosting sites (placeholder - actual scraping would be done manually or via external service)
export async function searchVideoSources(animeTitle: string, episode: number): Promise<{
  vidmoly: string[];
  sibnet: string[];
  sendvid: string[];
}> {
  // This is a placeholder - in production, you would:
  // 1. Use a scraping service
  // 2. Connect to an aggregator API
  // 3. Have users submit links manually

  console.log(`Searching for: ${animeTitle} Episode ${episode}`);

  return {
    vidmoly: [],
    sibnet: [],
    sendvid: [],
  };
}

