// AnimeAPI.net - Secondary source for missing episodes
// This module ONLY supplements Frivox data, never replaces it

const ANIMEAPI_BASE = 'https://animeapi.net';

interface AnimeAPIEpisode {
  id: string;
  episode: string;
  title: string;
  image: string | null;
  sub: {
    url: string;
    headers: Record<string, string>;
    subtitles: unknown[];
  } | null;
  dub: {
    url: string;
    headers: Record<string, string>;
    subtitles: unknown[];
  } | null;
}

interface AnimeAPIResult {
  id: string;
  title: string;
  image: string | null;
  provider: string;
  type: string;
  episodes: AnimeAPIEpisode[];
  score: number;
}

interface AnimeAPIResponse {
  status: string;
  query: string;
  type: string;
  results: AnimeAPIResult[];
}

// Cache for AnimeAPI responses (30 minutes)
const apiCache = new Map<string, {
  data: AnimeAPIResponse | null;
  timestamp: number;
}>();
const CACHE_TTL = 30 * 60 * 1000; // 30 minutes

// Rate limiting
let lastRequestTime = 0;
const MIN_REQUEST_INTERVAL = 500; // 500ms between requests

async function rateLimitedFetch(url: string): Promise<Response> {
  const now = Date.now();
  const timeSinceLastRequest = now - lastRequestTime;

  if (timeSinceLastRequest < MIN_REQUEST_INTERVAL) {
    await new Promise(resolve => setTimeout(resolve, MIN_REQUEST_INTERVAL - timeSinceLastRequest));
  }

  lastRequestTime = Date.now();
  return fetch(url);
}

/**
 * Search for an anime on AnimeAPI
 */
export async function searchAnimeAPI(title: string): Promise<AnimeAPIResponse | null> {
  const cacheKey = title.toLowerCase().trim();

  // Check cache
  const cached = apiCache.get(cacheKey);
  if (cached && Date.now() - cached.timestamp < CACHE_TTL) {
    return cached.data;
  }

  try {
    // Clean title for search (remove season indicators)
    const cleanTitle = title
      .replace(/\s*(saison|season|s)\s*\d+/i, '')
      .replace(/\s*\(\s*vf\s*\)/i, '')
      .replace(/\s*\(\s*vostfr\s*\)/i, '')
      .replace(/\s*-\s*$/, '')
      .trim();

    const response = await rateLimitedFetch(
      `${ANIMEAPI_BASE}/anime/${encodeURIComponent(cleanTitle)}`
    );

    if (!response.ok) {
      console.warn(`AnimeAPI: No results for "${cleanTitle}"`);
      apiCache.set(cacheKey, { data: null, timestamp: Date.now() });
      return null;
    }

    const data: AnimeAPIResponse = await response.json();

    if (data.status !== 'success' || !data.results || data.results.length === 0) {
      apiCache.set(cacheKey, { data: null, timestamp: Date.now() });
      return null;
    }

    apiCache.set(cacheKey, { data: data, timestamp: Date.now() });
    return data;

  } catch (error) {
    console.error(`AnimeAPI search error for "${title}":`, error);
    return null;
  }
}

/**
 * Get episode data from AnimeAPI for a specific anime and episode
 * Returns a URL that can be used in an iframe or video player
 */
export async function getEpisodeFromAnimeAPI(
  title: string,
  episodeNumber: number,
  preferDub: boolean = false
): Promise<{ url: string; provider: string } | null> {
  try {
    const searchData = await searchAnimeAPI(title);

    if (!searchData || !searchData.results || searchData.results.length === 0) {
      return null;
    }

    // Get the best result (first one usually)
    const result = searchData.results[0];

    // Find the episode
    const episode = result.episodes.find(
      ep => parseInt(ep.episode) === episodeNumber
    );

    if (!episode) {
      return null;
    }

    // Prefer dub if requested and available, otherwise sub
    const streamData = (preferDub && episode.dub) ? episode.dub : (episode.sub || episode.dub);

    if (!streamData || !streamData.url) {
      return null;
    }

    // Return the M3U8 URL with a proxy prefix for our player
    // The frontend will handle HLS playback
    return {
      url: streamData.url,
      provider: result.provider,
    };

  } catch (error) {
    console.error(`AnimeAPI episode fetch error:`, error);
    return null;
  }
}

/**
 * Get all available episodes from AnimeAPI for an anime
 */
export async function getAllEpisodesFromAnimeAPI(
  title: string
): Promise<Map<number, { sub: string | null; dub: string | null }>> {
  const episodes = new Map<number, { sub: string | null; dub: string | null }>();

  try {
    const searchData = await searchAnimeAPI(title);

    if (!searchData || !searchData.results || searchData.results.length === 0) {
      return episodes;
    }

    const result = searchData.results[0];

    for (const episode of result.episodes) {
      const epNum = parseInt(episode.episode);
      if (isNaN(epNum)) continue;

      episodes.set(epNum, {
        sub: episode.sub?.url || null,
        dub: episode.dub?.url || null,
      });
    }

    return episodes;

  } catch (error) {
    console.error(`AnimeAPI episodes fetch error:`, error);
    return episodes;
  }
}

/**
 * Get the max episode count from AnimeAPI for an anime
 */
export async function getMaxEpisodesFromAnimeAPI(title: string): Promise<number> {
  const episodes = await getAllEpisodesFromAnimeAPI(title);
  if (episodes.size === 0) return 0;
  return Math.max(...episodes.keys());
}

// Export cache stats for debugging
export function getAnimeAPICacheStats() {
  return {
    size: apiCache.size,
    entries: Array.from(apiCache.entries()).map(([key, value]) => ({
      title: key,
      hasData: value.data !== null,
      episodeCount: value.data?.results?.[0]?.episodes?.length || 0,
      age: Date.now() - value.timestamp,
    })),
  };
}

