import { db } from './db';

const TENSHITV_API = 'https://tenshitv.com/api';
const CACHE_DURATION = 60 * 60 * 1000; // 1 hour

// Types matching TenshiTV API
export interface TenshiTVAnime {
  id: number;
  title: string;
  slug: string;
  cover_url: string | null;
  banner_url: string | null;
  synopsis: string | null;
  available_languages: string;
  type: string;
  release_year: number | null;
  is_classic: number;
  episode_count: number;
  genres: { id: number; name: string }[];
}

export interface TenshiTVAnimeDetail extends TenshiTVAnime {
  created_at: string;
  last_update: string;
}

export interface TenshiTVEpisode {
  id: number;
  anime_id: number;
  season_label: string;
  episode_number: number;
  video_url: string;
  language: string;
  release_date: string | null;
  created_at: string;
  last_update: string;
  got_fixed: number;
}

export interface AnimeListResponse {
  animes: TenshiTVAnime[];
  total: number;
  page: number;
  limit: number;
  total_pages: number;
}

// Our internal anime type
export interface AnimeData {
  id: string;
  externalId: number;
  slug: string;
  title: string;
  coverImage: string | null;
  bannerImage: string | null;
  description: string | null;
  year: number | null;
  rating: number | null;
  episodeCount: number | null;
  type: string | null;
  isClassic: boolean;
  genres: string[];
  languages: string[];
  seasons: SeasonData[];
}

export interface SeasonData {
  title: string;
  seasonNumber: number;
  episodeCount: number;
  episodes: EpisodeData[];
}

export interface EpisodeData {
  id: number;
  episodeNumber: number;
  title: string;
  thumbnail: string | null;
  language: string;
  videoUrl: string;
}

// Cache helper
async function getCached<T>(key: string): Promise<T | null> {
  try {
    const cached = await db.cachedData.findUnique({
      where: { key },
    });

    if (cached && cached.expiresAt > new Date()) {
      return JSON.parse(cached.data) as T;
    }
  } catch (error) {
    console.error('Cache read error:', error);
  }
  return null;
}

async function setCache<T>(key: string, data: T): Promise<void> {
  try {
    await db.cachedData.upsert({
      where: { key },
      create: {
        key,
        data: JSON.stringify(data),
        expiresAt: new Date(Date.now() + CACHE_DURATION),
      },
      update: {
        data: JSON.stringify(data),
        expiresAt: new Date(Date.now() + CACHE_DURATION),
      },
    });
  } catch (error) {
    console.error('Cache write error:', error);
  }
}

// Fetch all animes from TenshiTV API
async function fetchAllAnimes(): Promise<TenshiTVAnime[]> {
  const allAnimes: TenshiTVAnime[] = [];
  let page = 1;
  const limit = 100;
  let totalPages = 1;

  try {
    // First request to get total pages
    const firstResponse = await fetch(`${TENSHITV_API}/animes?page=1&limit=${limit}`);
    if (!firstResponse.ok) {
      throw new Error(`Failed to fetch animes: ${firstResponse.status}`);
    }

    const firstData: AnimeListResponse = await firstResponse.json();
    allAnimes.push(...firstData.animes);
    totalPages = firstData.total_pages;

    console.log(`Fetching ${firstData.total} animes across ${totalPages} pages...`);

    // Fetch remaining pages
    const pagePromises: Promise<AnimeListResponse>[] = [];
    for (let p = 2; p <= totalPages; p++) {
      pagePromises.push(
        fetch(`${TENSHITV_API}/animes?page=${p}&limit=${limit}`).then(r => r.json())
      );
    }

    const remainingPages = await Promise.all(pagePromises);
    for (const pageData of remainingPages) {
      allAnimes.push(...pageData.animes);
    }

    console.log(`Successfully fetched ${allAnimes.length} animes`);
  } catch (error) {
    console.error('Error fetching all animes:', error);
    throw error;
  }

  return allAnimes;
}

// Convert TenshiTV anime to our format
function convertAnime(anime: TenshiTVAnime): AnimeData {
  return {
    id: anime.slug,
    externalId: anime.id,
    slug: anime.slug,
    title: anime.title,
    coverImage: anime.cover_url,
    bannerImage: anime.banner_url,
    description: anime.synopsis,
    year: anime.release_year,
    rating: null, // TenshiTV doesn't provide rating
    episodeCount: anime.episode_count,
    type: anime.type,
    isClassic: anime.is_classic === 1,
    genres: anime.genres?.map(g => g.name) || [],
    languages: anime.available_languages?.split(',') || [],
    seasons: [],
  };
}

// Get all animes (with caching)
export async function getAnimeList(): Promise<AnimeData[]> {
  const cacheKey = 'all_animes';

  // Check cache first
  const cached = await getCached<AnimeData[]>(cacheKey);
  if (cached) {
    console.log(`Returning ${cached.length} animes from cache`);
    return cached;
  }

  // Fetch from API
  try {
    const animes = await fetchAllAnimes();
    const converted = animes.map(convertAnime);

    // Cache the result
    await setCache(cacheKey, converted);

    return converted;
  } catch (error) {
    console.error('API fetch failed, trying stale cache:', error);

    // Try to use stale cache (expired but still in database)
    try {
      const staleEntry = await db.cachedData.findUnique({
        where: { key: cacheKey },
      });

      if (staleEntry) {
        const staleData = JSON.parse(staleEntry.data) as AnimeData[];
        console.log(`Returning ${staleData.length} animes from stale cache`);
        return staleData;
      }
    } catch (cacheErr) {
      console.error('Stale cache error:', cacheErr);
    }

    throw error;
  }
}

// Get anime by slug
export async function getAnimeBySlug(slug: string): Promise<AnimeData | null> {
  const cacheKey = `anime_${slug}`;

  // Check cache first
  const cached = await getCached<AnimeData>(cacheKey);
  if (cached) {
    return cached;
  }

  try {
    const response = await fetch(`${TENSHITV_API}/animes/${slug}`);
    if (!response.ok) {
      if (response.status === 404) return null;
      throw new Error(`Failed to fetch anime: ${response.status}`);
    }

    const anime: TenshiTVAnimeDetail = await response.json();
    const converted = convertAnime(anime);

    // Fetch episodes
    const episodes = await getEpisodesByAnimeId(anime.id);
    converted.seasons = groupEpisodesBySeason(episodes);

    // Cache the result
    await setCache(cacheKey, converted);

    return converted;
  } catch (error) {
    console.error(`Error fetching anime ${slug}:`, error);
    return null;
  }
}

// Get episodes by anime ID
export async function getEpisodesByAnimeId(animeId: number): Promise<TenshiTVEpisode[]> {
  const cacheKey = `episodes_${animeId}`;

  const cached = await getCached<TenshiTVEpisode[]>(cacheKey);
  if (cached) {
    return cached;
  }

  try {
    const response = await fetch(`${TENSHITV_API}/animes/${animeId}/episodes`);
    if (!response.ok) {
      throw new Error(`Failed to fetch episodes: ${response.status}`);
    }

    const episodes: TenshiTVEpisode[] = await response.json();

    // Cache the result
    await setCache(cacheKey, episodes);

    return episodes;
  } catch (error) {
    console.error(`Error fetching episodes for anime ${animeId}:`, error);
    return [];
  }
}

// Group episodes by season
function groupEpisodesBySeason(episodes: TenshiTVEpisode[]): SeasonData[] {
  const seasonMap = new Map<string, TenshiTVEpisode[]>();

  for (const ep of episodes) {
    const season = ep.season_label || 'Saison 1';
    if (!seasonMap.has(season)) {
      seasonMap.set(season, []);
    }
    seasonMap.get(season)!.push(ep);
  }

  const seasons: SeasonData[] = [];
  let seasonNumber = 1;

  for (const [title, eps] of seasonMap) {
    // Sort episodes by number
    eps.sort((a, b) => a.episode_number - b.episode_number);

    seasons.push({
      title,
      seasonNumber: seasonNumber++,
      episodeCount: eps.length,
      episodes: eps.map(ep => ({
        id: ep.id,
        episodeNumber: ep.episode_number,
        title: `Épisode ${ep.episode_number}`,
        thumbnail: null,
        language: ep.language,
        videoUrl: ep.video_url,
      })),
    });
  }

  return seasons;
}

// Get popular/trending anime (top rated classics and recent)
export async function getPopularAnime(): Promise<AnimeData[]> {
  const allAnimes = await getAnimeList();

  return allAnimes
    .filter(a => a.isClassic || (a.year && a.year >= 2022))
    .sort((a, b) => {
      // Prioritize classics
      if (a.isClassic && !b.isClassic) return -1;
      if (!a.isClassic && b.isClassic) return 1;
      // Then by year
      return (b.year || 0) - (a.year || 0);
    })
    .slice(0, 20);
}

// Get recent anime
export async function getRecentAnime(): Promise<AnimeData[]> {
  const allAnimes = await getAnimeList();

  return allAnimes
    .filter(a => a.year && a.year >= 2023)
    .sort((a, b) => (b.year || 0) - (a.year || 0))
    .slice(0, 20);
}

// Get featured anime for hero
export async function getFeaturedAnime(): Promise<AnimeData | null> {
  const allAnimes = await getAnimeList();

  // Try to find a classic with banner
  const featured = allAnimes.find(a => a.isClassic && a.bannerImage);
  if (featured) return featured;

  // Fall back to any anime with banner
  const withBanner = allAnimes.find(a => a.bannerImage);
  if (withBanner) return withBanner;

  // Last resort: any anime with cover
  return allAnimes.find(a => a.coverImage) || allAnimes[0] || null;
}

// Search anime
export async function searchAnime(query: string): Promise<AnimeData[]> {
  const allAnimes = await getAnimeList();
  const lowerQuery = query.toLowerCase();

  return allAnimes.filter(anime => 
    anime.title.toLowerCase().includes(lowerQuery) ||
    anime.genres?.some(g => g.toLowerCase().includes(lowerQuery)) ||
    anime.description?.toLowerCase().includes(lowerQuery)
  );
}

// Get filter options (genres, years, types, languages)
export async function getFilterOptions(): Promise<{
  genres: string[];
  years: number[];
  types: string[];
  languages: string[];
}> {
  const cacheKey = 'filter_options';

  const cached = await getCached<{
    genres: string[];
    years: number[];
    types: string[];
    languages: string[];
  }>(cacheKey);

  if (cached) return cached;

  const allAnimes = await getAnimeList();

  const genres = new Set<string>();
  const years = new Set<number>();
  const types = new Set<string>();
  const languages = new Set<string>();

  for (const anime of allAnimes) {
    anime.genres?.forEach(g => genres.add(g));
    if (anime.year) years.add(anime.year);
    if (anime.type) types.add(anime.type);
    anime.languages?.forEach(l => languages.add(l));
  }

  const result = {
    genres: Array.from(genres).sort(),
    years: Array.from(years).sort((a, b) => b - a),
    types: Array.from(types).sort(),
    languages: Array.from(languages).sort(),
  };

  await setCache(cacheKey, result);

  return result;
}

// Filter and sort animes
export interface FilterOptions {
  genre?: string;
  year?: number;
  type?: string;
  language?: string;
  isClassic?: boolean;
  search?: string;
  sortBy?: 'title_asc' | 'title_desc' | 'year_asc' | 'year_desc';
}

export async function getFilteredAnimes(
  options: FilterOptions,
  page: number = 1,
  limit: number = 50
): Promise<{
  animes: AnimeData[];
  total: number;
  page: number;
  totalPages: number;
  hasMore: boolean;
}> {
  let animes = await getAnimeList();

  // Apply search
  if (options.search) {
    const query = options.search.toLowerCase();
    animes = animes.filter(a => 
      a.title.toLowerCase().includes(query) ||
      a.genres?.some(g => g.toLowerCase().includes(query)) ||
      a.description?.toLowerCase().includes(query)
    );
  }

  // Apply genre filter
  if (options.genre) {
    animes = animes.filter(a => 
      a.genres?.some(g => g.toLowerCase() === options.genre?.toLowerCase())
    );
  }

  // Apply year filter
  if (options.year) {
    animes = animes.filter(a => a.year === options.year);
  }

  // Apply type filter
  if (options.type) {
    animes = animes.filter(a => a.type === options.type);
  }

  // Apply language filter
  if (options.language) {
    animes = animes.filter(a => 
      a.languages?.some(l => l === options.language)
    );
  }

  // Apply classic filter
  if (options.isClassic !== undefined) {
    animes = animes.filter(a => a.isClassic === options.isClassic);
  }

  // Apply sorting
  switch (options.sortBy) {
    case 'title_asc':
      animes.sort((a, b) => a.title.localeCompare(b.title));
      break;
    case 'title_desc':
      animes.sort((a, b) => b.title.localeCompare(a.title));
      break;
    case 'year_asc':
      animes.sort((a, b) => (a.year || 0) - (b.year || 0));
      break;
    case 'year_desc':
      animes.sort((a, b) => (b.year || 0) - (a.year || 0));
      break;
    default:
      animes.sort((a, b) => a.title.localeCompare(b.title));
  }

  // Apply pagination
  const total = animes.length;
  const totalPages = Math.ceil(total / limit);
  const start = (page - 1) * limit;
  const paginated = animes.slice(start, start + limit);

  return {
    animes: paginated,
    total,
    page,
    totalPages,
    hasMore: page < totalPages,
  };
}

// Export types
export type { AnimeData as Anime, SeasonData as Season, EpisodeData as Episode };

